import { NextResponse } from "next/server";

// Fake DB
let tasks: any[] = [
  { id: "task1", title: "Task 1", linkedProjectIds: [] },
];

export async function POST(req: Request) {
  const { taskId, projectIds } = await req.json();

  let updatedTask = null; // ✅ define variable

  tasks = tasks.map((task) => {
    if (task.id === taskId) {
      updatedTask = { ...task, linkedProjectIds: projectIds };
      return updatedTask;
    }
    return task;
  });

  return NextResponse.json({
    message: "Linked updated",
    task: updatedTask, // ✅ now valid
  });
}

import { NextResponse } from "next/server";
import dbConnect from "@/lib/dbConnect";
import Project from "@/lib/models/Project";
import { getAuthUser } from "@/lib/authUser";

type Role = "viewer" | "commenter" | "editor";

export async function GET(
  _req: Request,
  { params }: { params: Promise<{ id: string }> }
) {
  await dbConnect();
  const { id } = await params;

  const authUser = await getAuthUser();
  if (!authUser?.userId) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  const authEmail = String(authUser.email || "").trim().toLowerCase();

  const project = await Project.findOne({ _id: id }).select("ownerId collaborators");
  if (!project) {
    return NextResponse.json({ error: "Project not found" }, { status: 404 });
  }

  const isOwner = String(project.ownerId) === String(authUser.userId);
  const isCollaborator = Array.isArray(project.collaborators)
    ? project.collaborators.some((c: any) => String(c.email || "").toLowerCase() === authEmail)
    : false;

  if (!isOwner && !isCollaborator) {
    return NextResponse.json({ error: "Forbidden" }, { status: 403 });
  }

  return NextResponse.json({
    success: true,
    collaborators: project.collaborators || [],
  });
}

