"use client";

import { useSearchParams } from "next/navigation";
import { useEffect, useState } from "react";
import { SpinnerFullscreen } from "@/components/ui/spinner";

interface CalendarItem {
  _id: string;
  title: string;
  startDate: string;
  endDate: string;
}

export default function CalendarPage() {
  const search = useSearchParams();
  const databaseId = search.get("databaseId");

  const [items, setItems] = useState<CalendarItem[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    if (!databaseId) {
      setIsLoading(false);
      return;
    }

    setIsLoading(true);
    fetch(`/api/database-items?databaseId=${databaseId}`)
      .then((r) => r.json())
      .then((data) => {
        setItems(data);
        setIsLoading(false);
      })
      .catch(() => setIsLoading(false));
  }, [databaseId]);

  if (isLoading) {
    return (
      <div className="min-h-screen bg-white p-10">
        <SpinnerFullscreen text="Loading calendar..." />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-white p-10">
      <h1 className="text-2xl font-bold">Calendar View</h1>
      <p className="text-sm text-gray-500 mt-2">
        (Simple list now — later you can render a real calendar grid)
      </p>

      <div className="mt-6 space-y-3">
        {items.map((it) => (
          <div key={it._id} className="border rounded-xl p-4">
            <div className="font-semibold">{it.title}</div>
            <div className="text-sm text-gray-500">
              {new Date(it.startDate).toDateString()} →{" "}
              {new Date(it.endDate).toDateString()}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { useParams } from "next/navigation";
import EditorComponent from "@/components/notion-editior/EditorComponent";
import "@/styles/editor.css";

export default function EditPage() {
  const params = useParams();
  const rawId = params?.id;
  const id = Array.isArray(rawId) ? rawId[0] : rawId;
  const [data, setData] = useState<any>(null);
  const [hasLoaded, setHasLoaded] = useState(false);

  useEffect(() => {
    if (!id) {
      setHasLoaded(true);
      return;
    }

    // Fetch existing data on mount
    const fetchData = async () => {
      try {
        const res = await fetch(`/api/editor/${id}`);
        if (res.ok) {
          const result = await res.json();
          console.log("Fetched:", result);
          if (result?.content) {
            setData(result.content);
          }
        }
      } catch (err) {
        console.error("Error fetching editor data:", err);
      } finally {
        setHasLoaded(true);
      }
    };

    fetchData();
  }, [id]);

  return (
    <div className="p-6">
      <h1 className="text-2xl font-bold mb-4">Editor</h1>
      {hasLoaded && <EditorComponent initialData={data} docId={id} />}
    </div>
  );
}

