                    {event.time}
                </span>
            </div>
            
            <div className={`flex items-center gap-3 mt-2 text-xs ${textMuted}`}>
                <div className="flex items-center gap-1">
                    <MapPin size={14} />
                    <span>{event.location}</span>
                </div>
            </div>
