            {/* Sidebar */}
            <div className={`
                fixed lg:sticky top-0 right-0 h-full lg:h-auto
                w-[280px] sm:w-[300px] lg:w-[300px] 
                shrink-0 p-4 sm:p-6 rounded-none lg:rounded-3xl 
                border-l lg:border ${cardBg} 
                lg:top-8 space-y-4 sm:space-y-6 
                z-50 lg:z-auto
