// ─── OTP Form ─────────────────────────────────────────────
function OtpForm({ otp, onChange, onSubmit, loading, error, onBack }: {
  otp: string[];
  onChange: (v: string, i: number) => void;
  onSubmit: () => void;
  loading: boolean;
  error: string;
  onBack: () => void;
}) {
  return (
    <div className="am-form-inner">
      <div className="am-form-title">Verify Email</div>
