import { useAuth } from "./AuthContext";

/* ── palette for initial-based avatars ── */
const AVATAR_COLORS = [
  "bg-violet-500", "bg-indigo-500", "bg-sky-500",
  "bg-emerald-500", "bg-pink-500",  "bg-amber-500",
  "bg-rose-500",   "bg-teal-500",
];

