'use client';

import { Moon, Sun } from 'lucide-react';
import { useEffect, useState } from 'react';

import { Button } from '@/components/ui/button';

export default function ThemeToggle() {
  const [isDark, setIsDark] = useState(false);

  useEffect(() => {
    if (typeof window === 'undefined') return;
    const stored = window.localStorage.getItem('theme');
    const prefersDark = window.matchMedia('(prefers-color-scheme: dark)')
      .matches;
    const nextTheme = stored ?? (prefersDark ? 'dark' : 'light');
    setIsDark(nextTheme === 'dark');
    document.documentElement.classList.toggle('dark', nextTheme === 'dark');
  }, []);

  const toggleTheme = () => {
    setIsDark((prev) => {
      const next = !prev;
      if (typeof document !== 'undefined') {
        document.documentElement.classList.toggle('dark', next);
      }
      if (typeof window !== 'undefined') {
        window.localStorage.setItem('theme', next ? 'dark' : 'light');
      }
      return next;
    });
  };

  return (
    <Button
      variant="ghost"
      size="icon"
      onClick={toggleTheme}
      className="border border-white/10 shadow-inner shadow-black/10"
      aria-label="Toggle color mode"
    >
      {isDark ? <Moon size={18} /> : <Sun size={18} />}
    </Button>
  );
}

"use client";

import { useEffect, useState } from "react";
import Modal from "@/components/Modal";

export default function TimelineItemModal({
  isOpen,
  onClose,
  item,
  isDark,
  onSaved,
}: {
  isOpen: boolean;
  onClose: () => void;
  item: any;
  isDark: boolean;
  onSaved: () => void;
}) {
  const [form, setForm] = useState({
    title: "",
    startDate: "",
    endDate: "",
    assignedTo: "",
    status: "Todo",
    comment: "",
  });

  useEffect(() => {
    if (!item) return;

    setForm({
      title: item.title || "",
      startDate: item.startDate?.slice(0, 10) || "",
      endDate: item.endDate?.slice(0, 10) || "",
      assignedTo: item.assignedTo || "",
      status: item.status || "Todo",
      comment: item.comment || "",
    });
  }, [item]);

  const save = async () => {
    const payload = {
      title: form.title,
      startDate: form.startDate ? new Date(form.startDate).toISOString() : null,
      endDate: form.endDate ? new Date(form.endDate).toISOString() : null,
      assignedTo: form.assignedTo,
      status: form.status,
      comment: form.comment,
    };

    console.log('=== SAVE DEBUG ===');
    console.log('Form state:', form);
    console.log('Saving item ID:', item._id);
    console.log('Payload being sent:', JSON.stringify(payload, null, 2));

    const res = await fetch(`/api/timeline/${item._id}`, {
      method: "PATCH",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload),
    });

    if (!res.ok) {
      const errorText = await res.text();
      console.error("Failed to save:", errorText);
      alert("Failed to save changes: " + errorText);
      return;
    }

    const result = await res.json();
    console.log('Save result from API:', result);
    console.log('assignedTo in result:', result.assignedTo);
    console.log('comment in result:', result.comment);

    onSaved();
    onClose();
  };

  const remove = async () => {
    if (!confirm("Delete this item?")) return;

    await fetch(`/api/timeline/${item._id}`, {
      method: "DELETE",
    });

    onSaved();
    onClose();
  };

  return (
    <Modal isOpen={isOpen} onClose={onClose} title="Edit Timeline Card" isDark={isDark}>
      <div className="space-y-4 sm:space-y-5">
