  chartType: ChartType;
  xAxisKey: string;
  yAxisKeys: string[];
  colors: string[];
  showLegend: boolean;
  showGrid: boolean;
  showTooltip: boolean;
  dataLabels: boolean;
  curved: boolean;
  stacked: boolean;
  fillOpacity: number;
  linkedTableId: string | null;
  showDots: boolean;
  strokeWidth: number;
  borderRadius: number;
  bgColor: string;
}

interface LinkedDB {
