"use client";

import { useEffect, useState } from "react";
import { useTheme } from "next-themes";

import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Separator } from "@/components/ui/separator";
import { ScrollArea } from "@/components/ui/scroll-area";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
} from "@/components/ui/tooltip";

import { Trash2 } from "lucide-react";

type HeadingBlock = {
  _id: string;
  databaseId: string;
  text: string;
  level: "h1" | "h2" | "h3";
};

export default function HeadingView({ databaseId }: { databaseId: string }) {
  const { resolvedTheme } = useTheme();
  const isDark = resolvedTheme === "dark";

  const [headings, setHeadings] = useState<HeadingBlock[]>([]);
  const [loading, setLoading] = useState(true);

  const fetchAll = async () => {
    setLoading(true);
    const res = await fetch(`/api/heading?databaseId=${databaseId}`);
    setHeadings(await res.json());
    setLoading(false);
  };

  useEffect(() => {
    fetchAll();
  }, [databaseId]);

  // Seed default headings (Notion style)
  useEffect(() => {
    const seed = async () => {
      const res = await fetch(`/api/heading?databaseId=${databaseId}`);
      const data = await res.json();

      if (data.length > 0) return;

      const defaults: Array<{ text: string; level: "h1" | "h2" | "h3" }> = [
        { text: "Heading 1", level: "h1" },
        { text: "Heading 2", level: "h2" },
        { text: "Heading 3", level: "h3" },
      ];

      for (const h of defaults) {
        await fetch("/api/heading", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            databaseId,
            text: h.text,
            level: h.level,
          }),
        });
      }

      fetchAll();
    };

    seed();
  }, [databaseId]);

  const updateHeading = async (id: string, body: any) => {
    await fetch(`/api/heading/${id}`, {
      method: "PATCH",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(body),
    });
  };

  const createHeading = async (level: "h1" | "h2" | "h3") => {
    const res = await fetch("/api/heading", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        databaseId,
        text: "",
        level,
      }),
    });

    const created = await res.json();
    setHeadings((prev) => [...prev, created]);
  };

  const deleteHeading = async (id: string) => {
    await fetch(`/api/heading/${id}`, { method: "DELETE" });
    setHeadings((prev) => prev.filter((x) => x._id !== id));
  };

  const getHeadingSize = (level: "h1" | "h2" | "h3") => {
    if (level === "h1") return "text-3xl font-bold";
    if (level === "h2") return "text-2xl font-bold";
    return "text-xl font-semibold";
  };

  if (loading) {
    return (
      <div className={`p-6 text-sm ${isDark ? "text-gray-400" : "text-gray-600"}`}>
        Loading...
      </div>
    );
  }

  return (
    <TooltipProvider>
      <Card className={`${!isDark ? "bg-gray-100" : ""} rounded-xl border overflow-hidden`}>
        <CardHeader className="flex flex-row items-center justify-between">
          <CardTitle>Headings</CardTitle>

          <div className="flex gap-2">
            <Button size="sm" variant="outline" onClick={() => createHeading("h1")}>
              + H1
            </Button>
            <Button size="sm" variant="outline" onClick={() => createHeading("h2")}>
              + H2
            </Button>
            <Button size="sm" variant="outline" onClick={() => createHeading("h3")}>
              + H3
            </Button>
          </div>
        </CardHeader>

        <Separator />

        <CardContent className="p-0">
          <ScrollArea className="h-[320px]">
            <div className="p-4 space-y-4">
              {headings.map((h) => (
                <div key={h._id} className={`flex items-start gap-3 border rounded-md px-3 py-2 ${!isDark ? 'bg-rose-50' : ''}`}>
                  {/* Level Select */}
                  <Select
                    value={h.level}
                    onValueChange={(level: "h1" | "h2" | "h3") => {
                      setHeadings((prev) =>
                        prev.map((x) => (x._id === h._id ? { ...x, level } : x))
                      );
                      updateHeading(h._id, { level });
                    }}
                  >
                    <SelectTrigger className={`w-[80px] ${isDark ? "bg-[#18191d]" : ""}`}>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent className={isDark ? "bg-[#1e1f23] border-gray-700" : "bg-white"}>
                      <SelectItem value="h1">H1</SelectItem>
                      <SelectItem value="h2">H2</SelectItem>
                      <SelectItem value="h3">H3</SelectItem>
                    </SelectContent>
                  </Select>

                  {/* Heading Input */}
                  <Input
                    value={h.text}
                    placeholder="Heading..."
                    onChange={(e) => {
                      const text = e.target.value;
                      setHeadings((prev) =>
                        prev.map((x) => (x._id === h._id ? { ...x, text } : x))
                      );
                      updateHeading(h._id, { text });
                    }}
                    className={`border-none shadow-none focus-visible:ring-0 px-0 ${getHeadingSize(
                      h.level
                    )}`}
                  />

                  {/* Delete */}
                  <Tooltip>
                    <TooltipTrigger asChild>
                      <Button
                        size="icon"
                        variant="ghost"
                        onClick={() => deleteHeading(h._id)}
                      >
                        <Trash2 className="h-4 w-4" />
                      </Button>
                    </TooltipTrigger>
                    <TooltipContent>Delete</TooltipContent>
                  </Tooltip>
                </div>
              ))}
            </div>
          </ScrollArea>
        </CardContent>
      </Card>
    </TooltipProvider>
  );
}

export default class CalloutTool {
  data: any;
  wrapper: HTMLElement;

  constructor({ data }: any) {
    this.data = data || {};
    this.wrapper = document.createElement("div");
  }

  static get toolbox() {
    return {
      title: "Callout",
      icon: "💡",
    };
  }

  render() {
    this.wrapper.classList.add("callout");

    const input = document.createElement("div");
    input.contentEditable = "true";
    input.innerText = this.data.text || "Write callout...";

    input.oninput = () => {
      this.data.text = input.innerText;
    };

    this.wrapper.appendChild(input);

    return this.wrapper;
  }

  save() {
    return this.data;
  }
}

"use client";

import { useCallback, useEffect, useId, useRef, useState } from "react";
import "@/styles/editor.css";
import EditorJS, { type OutputData, type ToolConstructable } from "@editorjs/editorjs";

import Header from "@editorjs/header";
import List from "@editorjs/list";
import Table from "@editorjs/table";
import Delimiter from "@editorjs/delimiter";
import Quote from "@editorjs/quote";
import CalloutTool from "./CallutTools";
import ToggleTool from "./ToggleTolls";
import PageLinkTool from "./pageLink";
import TimelineBlockTool from "./TimelineBlockTool";
import BoardBlockTool from "./BoardBlockTool";
import TableBlockTool from "./TableBlockTool";
import Image from "next/image";
import type { StaticImageData } from "next/image";
import textPreview from "../../public/0Jl54.png";
import headerPreview from "../../public/c956c7564a558bd2e5f09c5a76352d17.jpg";
import linkPreview from "@/public/uploads/1771517084456-Screenshot-(2).png";

type PreviewState = {
  visible: boolean;
  top: number;
  left: number;
  title: string;
  description: string;
  url: StaticImageData;
};

type EditorComponentProps = {
  initialData?: unknown;
  docId?: string;
  databaseId?: string;
};

export default function EditorComponent({ initialData, docId, databaseId }: EditorComponentProps) {
  const editorRef = useRef<EditorJS | null>(null);
  const initialDataRef = useRef<OutputData | undefined>(initialData as OutputData | undefined);
  const autoSaveRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const previewRef = useRef<HTMLDivElement | null>(null);
  const holderId = useId().replace(/:/g, "_");
  const [currentDocId, setCurrentDocId] = useState<string | undefined>(docId);
  const [isLoading, setIsLoading] = useState(!docId && !!databaseId);
  const [saveStatus, setSaveStatus] = useState<string>("");
  const [preview, setPreview] = useState<PreviewState>({
    visible: false,
    top: 0,
    left: 0,
    title: "",
    description: "",
    url: textPreview,
  });

  const handleSave = useCallback(async () => {
    if (!editorRef.current) return;

    setSaveStatus("Saving...");
    const data = await editorRef.current.save();

    try {
      let saveDocId = currentDocId;

      // If no docId, create new editor document
      if (!saveDocId) {
        const res = await fetch(`/api/editor`, {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
          },
          body: JSON.stringify(data),
        });

        if (!res.ok) {
          setSaveStatus("Save failed");
          setTimeout(() => setSaveStatus(""), 800);
          return;
        }

        const result = await res.json();
        saveDocId = result.data?._id;
        setCurrentDocId(saveDocId);
        console.log("Created new editor with ID:", saveDocId);
      } else {
        // Update existing editor
        const res = await fetch(`/api/editor/${saveDocId}`, {
          method: "PUT",
          headers: {
            "Content-Type": "application/json",
          },
          body: JSON.stringify(data),
        });

        if (!res.ok) {
          setSaveStatus("Save failed");
          setTimeout(() => setSaveStatus(""), 800);
          return;
        }
      }

      setSaveStatus("Saved successfully!");
      setTimeout(() => setSaveStatus(""), 2000);
    } catch (err) {
      console.error("Save error:", err);
      setSaveStatus("Save error");
      setTimeout(() => setSaveStatus(""), 800);
    }
  }, [currentDocId]);

  const handleAutoSave = useCallback(() => {
    if (autoSaveRef.current) {
      clearTimeout(autoSaveRef.current);
    }

    autoSaveRef.current = setTimeout(() => {
      void handleSave();
    }, 800);
  }, [handleSave]);

  // Fetch initial data if only databaseId is provided
  useEffect(() => {
    if (databaseId && !docId && !currentDocId) {
      const fetchData = async () => {
        try {
          const res = await fetch(`/api/editor/${databaseId}`);
          if (res.ok) {
            const result = await res.json();
            initialDataRef.current = result?.content as OutputData;
            setCurrentDocId(databaseId);
          } else if (res.status === 404) {
            // No existing data, start with blank editor
            setCurrentDocId(databaseId);
          }
        } catch (err) {
          console.error("Error fetching editor data:", err);
          setCurrentDocId(databaseId);
        } finally {
          setIsLoading(false);
        }
      };

      fetchData();
    } else if (docId) {
      setCurrentDocId(docId);
      setIsLoading(false);
    }
  }, [currentDocId, databaseId, docId]);
  useEffect(() => {
    if (isLoading) return;

    const editor = new EditorJS({
      holder: holderId,
      data: initialDataRef.current,
      tools: {
        header: {
          class: Header as unknown as ToolConstructable,
          inlineToolbar: true,},
        list: {
          class: List,
          inlineToolbar: true,
        },
        table: Table,
        delimiter: Delimiter,
        quote: Quote,
        callout: CalloutTool,
        toggle: ToggleTool,
        pagelink: PageLinkTool,
        board: {
          class: BoardBlockTool as unknown as ToolConstructable,
          config: {
            databaseId: databaseId ?? currentDocId ?? "",
          },
        },
        tableview: {
          class: TableBlockTool as unknown as ToolConstructable,
          config: {
            databaseId: databaseId ?? currentDocId ?? "",
          },
        },
        timeline: {
          class: TimelineBlockTool as unknown as ToolConstructable,
          config: {
            databaseId: databaseId ?? currentDocId ?? "",
          },
        },
      },
      onChange: () => {
        handleAutoSave();
      },
      onReady: () => {
        editorRef.current = editor;
      },
    });

    return () => {
      if (autoSaveRef.current) {
        clearTimeout(autoSaveRef.current);
      }
      if (editorRef.current?.destroy) {
        editorRef.current.destroy();
        editorRef.current = null;
      }
    };
  }, [currentDocId, holderId, isLoading, handleAutoSave]);

  useEffect(() => {
    if (preview.visible && previewRef.current) {
      previewRef.current.style.top = `${preview.top}px`;
      previewRef.current.style.left = `${preview.left}px`;
    }
  }, [preview]);

  useEffect(() => {
    const hidePreview = () => {
      setPreview((prev) => ({ ...prev, visible: false }));
    };

    const onPointerOver = (event: MouseEvent) => {
      const target = event.target as HTMLElement;
      const menuItem = target.closest(".ce-popover-item, .ce-toolbox__button") as HTMLElement | null;
      if (!menuItem) {
        hidePreview();
        return;
      }

      const rawText = (menuItem.textContent || "").toLowerCase().replace(/\s+/g, " ").trim();
      let title = "";
      let description = "";
      let url: StaticImageData = textPreview;

      if (rawText.includes("text") || rawText.includes("paragraph")) {
        title = "Text";
        description = "Start writing plain text content.";
        url = textPreview;
      } else if (rawText.includes("header") || rawText.includes("heading")) {
        title = "Header";
        description = "Add a section heading to structure your page.";
        url = headerPreview;
      } else if (rawText.includes("page link") || rawText.includes("pagelink")) {
        title = "Page Link";
        description = "Link this block to another page or resource.";
        url = linkPreview;
      } else if (rawText.includes("table view")) {
        title = "Table View";
        description = "Insert a full table section in this editor page.";
        url = textPreview;
      } else if (rawText.includes("table")) {
        title = "Table";
        description = "Add a table to organize your data.";
        url = textPreview;
      } else if (rawText.includes("toggle")) {
        title = "Toggle";
        description = "Add a toggleable section to your page.";
        url = textPreview;
      } else if (rawText.includes("list")) {
        title = "List";
        description = "Add a bulleted or numbered list to your page.";
        url = textPreview;
      } else if (rawText.includes("quote")) {
        title = "Quote";
        description = "Add a quoted text block to your page.";
        url = textPreview;
      } else if (rawText.includes("delimiter")) {
        title = "Delimiter";
        description = "Add a visual separator to your page.";
        url = textPreview;
      } else if (rawText.includes("callout")) {
        title = "Callout";
        description = "Add a callout block to your page.";
        url = textPreview;
      } else if (rawText.includes("timeline")) {
        title = "Timeline";
        description = "Insert a full timeline section in this editor page.";
        url = textPreview;
      } else if (rawText.includes("board")) {
        title = "Board";
        description = "Insert a full board section in this editor page.";
        url = textPreview;
      } else {
        hidePreview();
        return;
      }

      const rect = menuItem.getBoundingClientRect();
      setPreview({
        visible: true,
        top: rect.top + rect.height / 2,
        left: rect.right + 12,
        title,
        description,
        url,
      });
    };

    document.addEventListener("mouseover", onPointerOver);
    document.addEventListener("scroll", hidePreview, true);

    return () => {
      document.removeEventListener("mouseover", onPointerOver);
      document.removeEventListener("scroll", hidePreview, true);
    };
  }, []);

  if (isLoading) {
    return <div className="text-center py-8">Loading editor...</div>;
  }

  return (
    <div>
      <div className="mt-4 text-right mr-2 items-center gap-4">
        {/* <p
          onClick={() => void handleSave()}
          className="px-4 py-2 bg-transparent text-white rounded hover:bg-blue-600 transition"
        > */}
          {/* Save Now */}
        {/* </p> */}
        {saveStatus && (
          <span className={`text-sm ${
            saveStatus.includes("Saved") ? "text-green-600" : "text-gray-600"
          }`}>
            {saveStatus}
          </span>
        )}
      </div>
      <div id={holderId} className="editor-box" />
    

      {/* <div className="mt-4 items-center gap-4">
        <p
          onClick={() => void handleSave()}
          className="px-4 py-2 bg-transparent text-white rounded hover:bg-blue-600 transition"
        >
          Save Now
        </p>
        {saveStatus && (
          <span className={`text-sm ${
            saveStatus.includes("Saved") ? "text-green-600" : "text-gray-600"
          }`}>
            {saveStatus}
          </span>
        )}
      </div> */}

      {preview.visible && (
        <div
          ref={previewRef}
          className="fixed -translate-y-1/2 bg-gray-800 text-gray-50 rounded-xl px-3 py-2 w-[250px] shadow-2xl z-9999 pointer-events-none"
        >
          <div className="text-[13px] font-bold mb-1">{preview.title}</div>
          <div className="text-xs opacity-90">{preview.description}</div>
          <Image src={preview.url} alt="Preview Image" className="mt-2 rounded" />
        </div>
      )}
    </div>
  );
}

import { showPreview, hidePreview } from "./preview";
export default class PageTool {
  data: any;
  wrapper: HTMLElement;

  constructor({ data }: any) {
    this.data = data || {};
    this.wrapper = document.createElement("div");
  }

  static get toolbox() {
    return {
      title: "Page",
      icon: "📄",
    };
  }

  render() {
  this.wrapper.classList.add("page-link");

  const link = document.createElement("div");
  link.innerText = this.data.url || "Hover me";
  link.classList.add("page-link-text");

  // ✅ HOVER EVENT
  link.onmouseenter = (e) => {
    showPreview(e, this.data.url);
  };

  link.onmouseleave = () => {
    hidePreview();
  };

  this.wrapper.appendChild(link);

  return this.wrapper;
}

  save() {
    return this.data;
  }
}

export default class ToggleTool {
  data: any;
  wrapper: HTMLElement;

  constructor({ data }: any) {
    this.data = data || {};
    this.wrapper = document.createElement("div");
  }

  static get toolbox() {
    return {
      title: "Toggle",
      icon: "▶️",
    };
  }

  render() {
    const details = document.createElement("details");

    const summary = document.createElement("summary");
    summary.innerText = this.data.title || "Toggle";

    const content = document.createElement("div");
    content.contentEditable = "true";
    content.innerText = this.data.content || "Hidden content";

    content.oninput = () => {
      this.data.content = content.innerText;
    };

    details.appendChild(summary);
    details.appendChild(content);

    this.wrapper.appendChild(details);

    return this.wrapper;
  }

  save() {
    return this.data;
  }
}

