"use client";

import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import { useTheme } from "next-themes";
import AddPropertyPicker from "./TodoAddpropertyPicker";

import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";

import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { Checkbox } from "@/components/ui/checkbox";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Separator } from "@/components/ui/separator";

type Property = {
  _id: string;
  databaseId: string;
  name: string;
  type: string;
  options?: string[];
};

type Task = {
  _id: string;
  databaseId: string;
  title?: string;
  completed?: boolean;
  values: Record<string, any>;
};

export default function TodoTaskModal({
  isOpen,
  onClose,
  databaseId,
  taskId,
  properties,
  onUpdated,
}: {
  isOpen: boolean;
  onClose: () => void;
  databaseId: string;
  taskId: string | null;
  properties: Property[];
  onUpdated: () => void;
}) {
  const { resolvedTheme } = useTheme();
  const isDark = resolvedTheme === "dark";

  const [task, setTask] = useState<Task | null>(null);
  const [loading, setLoading] = useState(true);
  const [localTitle, setLocalTitle] = useState("");
  const titleDebounceTimer = useRef<NodeJS.Timeout | null>(null);
  const isEditingTitle = useRef(false);

  const [showAddProp, setShowAddProp] = useState(false);

  const titleProp = useMemo(
    () => properties.find((p) => p.type === "title"),
    [properties]
  );

  // Debug logging
  useEffect(() => {
    console.log("TodoTaskModal - titleProp:", titleProp);
    console.log("TodoTaskModal - task:", task);
    console.log("TodoTaskModal - properties:", properties);
    console.log("TodoTaskModal - showAddProp:", showAddProp);
  }, [titleProp, task, properties, showAddProp]);

  // Sync localTitle when task changes (but not while user is typing)
  useEffect(() => {
    if (task && !isEditingTitle.current) {
      const titleValue = task.title || "";
      console.log("Syncing localTitle from task.title:", titleValue);
      setLocalTitle(titleValue);
    }
  }, [task]);

  // Cleanup debounce timer
  useEffect(() => {
    return () => {
      if (titleDebounceTimer.current) {
        clearTimeout(titleDebounceTimer.current);
      }
    };
  }, []);

  const fetchTask = useCallback(async () => {
    if (!taskId) return;

    setLoading(true);
    const res = await fetch(`/api/todo/tasks/${taskId}`);
    const data = await res.json();

    if (!data.values) {
      data.values = {};
    }

    setTask(data);
    setLocalTitle(data.title || "");
    isEditingTitle.current = false;
    setLoading(false);
  }, [taskId]);

  useEffect(() => {
    if (!isOpen) return;
    fetchTask();
  }, [isOpen, fetchTask]);

  const updateValues = async (newValues: any) => {
    if (!task) {
      console.log("updateValues - No task found");
      return;
    }

    console.log("updateValues - Updating task:", task._id);
    console.log("updateValues - New values:", newValues);

    setTask({ ...task, values: newValues || {} });

    try {
      const response = await fetch(`/api/todo/tasks/${task._id}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ values: newValues }),
      });

      if (!response.ok) {
        console.error("updateValues - API error:", response.status, response.statusText);
        const errorData = await response.json().catch(() => ({}));
        console.error("updateValues - Error data:", errorData);
        return;
      }

      const updatedTask = await response.json();
      console.log("updateValues - Successfully updated task:", updatedTask);

      if (!updatedTask.values) {
        updatedTask.values = {};
      }

      setTask(updatedTask);
    } catch (error) {
      console.error("updateValues - Fetch error:", error);
    }
  };

  const setValue = (propId: string, value: any) => {
    console.log("setValue called - propId:", propId, "value:", value);
    console.log("task before setValue:", task);

    if (!task) {
      console.log("No task, returning...");
      return;
    }

    const newValues = {
      ...(task.values || {}),
      [propId]: value,
    };

    console.log("newValues:", newValues);
    updateValues(newValues);
  };

  const normalizeUrl = (value: string) => {
    const v = value.trim();
    if (!v) return "";
    if (v.startsWith("http://") || v.startsWith("https://")) return v;
    return `https://${v}`;
  };

  const filledProps = useMemo(() => {
    if (!task) return [];
    return properties.filter((p) => {
      if (p.type === "title") return false;
      const v = task.values?.[p._id];
      return (
        v !== undefined &&
        v !== null &&
        v !== "" &&
        !(Array.isArray(v) && v.length === 0)
      );
    });
  }, [properties, task]);

  const emptyProps = useMemo(() => {
    if (!task) return [];
    return properties.filter((p) => {
      if (p.type === "title") return false;
      const v = task.values?.[p._id];
      return (
        v === undefined ||
        v === null ||
        v === "" ||
        (Array.isArray(v) && v.length === 0)
      );
    });
  }, [properties, task]);

  const selectClass = `w-full border rounded-md px-3 py-2 text-sm ${
    isDark
      ? "bg-[#18191d] border-gray-700 text-gray-100"
      : "bg-white border-gray-200 text-gray-900"
  }`;

  const renderPropertyInput = (p: Property) => {
    if (!task) return null;
    const v = task.values?.[p._id] ?? (task.values || {})[p._id];

    switch (p.type) {
      case "text":
        return (
          <Input
            value={v || ""}
            onChange={(e) => setValue(p._id, e.target.value)}
            placeholder="Enter text..."
          />
        );

      case "number":
        return (
          <Input
            type="number"
            value={v || ""}
            onChange={(e) => setValue(p._id, e.target.value)}
            placeholder="Enter number..."
          />
        );

      case "date": {
        const dateValue = v ? new Date(v).toISOString().split("T")[0] : "";
        return (
          <Input
            type="date"
            value={dateValue}
            onChange={(e) => setValue(p._id, e.target.value)}
          />
        );
      }

      case "email": {
        const sendEmail = async (email: string) => {
          try {
            await fetch("/api/send-email", {
              method: "POST",
              headers: {
                "Content-Type": "application/json",
              },
              body: JSON.stringify({ email }),
            });
          } catch (err) {
            console.error("Email send failed", err);
          }
        };

        return (
          <Input
            type="email"
            value={v || ""}
            placeholder="email@example.com"
            onChange={(e) => setValue(p._id, e.target.value)}
            onBlur={(e) => {
              const email = e.target.value;
              if (email && email.includes("@")) {
                sendEmail(email);
              }
            }}
          />
        );
      }

      case "checkbox":
        return (
          <div className="flex items-center gap-2">
            <Checkbox
              checked={!!v}
              onCheckedChange={(checked) => setValue(p._id, Boolean(checked))}
            />
            <span className="text-sm text-muted-foreground">Enabled</span>
          </div>
        );

      case "select":
        return (
          <select
            value={v || ""}
            onChange={(e) => setValue(p._id, e.target.value)}
            className={selectClass}
          >
            <option value="">Select...</option>
            {(p.options || []).map((opt) => (
              <option key={opt} value={opt}>
                {opt}
              </option>
            ))}
          </select>
        );

      case "multi_select": {
        const multiValues = Array.isArray(v) ? v : [];
        return (
          <div className="space-y-2">
            <div className="flex flex-wrap gap-1">
              {multiValues.map((tag: string) => (
                <Badge
                  key={tag}
                  variant="default"
                  className="px-2 py-1 text-xs flex items-center gap-1"
                >
                  {tag}
                  <button
                    onClick={() =>
                      setValue(
                        p._id,
                        multiValues.filter((t) => t !== tag)
                      )
                    }
                    className={isDark ? "hover:text-gray-200" : "hover:text-gray-900"}
                  >
                    ×
                  </button>
                </Badge>
              ))}
            </div>
            <select
              value=""
              onChange={(e) => {
                if (e.target.value && !multiValues.includes(e.target.value)) {
                  setValue(p._id, [...multiValues, e.target.value]);
                }
              }}
              className={selectClass}
            >
              <option value="">Select an option...</option>
              {(p.options || []).map((opt) => (
                <option key={opt} value={opt}>
                  {opt}
                </option>
              ))}
            </select>
          </div>
        );
      }

      case "person":
        return (
          <Input
            value={v || ""}
            onChange={(e) => setValue(p._id, e.target.value)}
            placeholder="Enter name..."
          />
        );

      case "url": {
        const url = v || "";
        return (
          <div className="space-y-2">
            <Input
              type="url"
              value={url}
              onChange={(e) => setValue(p._id, e.target.value)}
              placeholder="https://example.com"
            />
            {url && (
              <a
                href={normalizeUrl(url)}
                target="_blank"
                rel="noopener noreferrer"
                className="inline-flex items-center gap-1 text-sm text-blue-600 hover:underline"
              >
                <svg
                  xmlns="http://www.w3.org/2000/svg"
                  className="h-4 w-4"
                  fill="none"
                  viewBox="0 0 24 24"
                  stroke="currentColor"
                >
                  <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    strokeWidth={2}
                    d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14"
                  />
                </svg>
                Open link
              </a>
            )}
          </div>
        );
      }

      default:
        return (
          <Input
            value={v || ""}
            onChange={(e) => setValue(p._id, e.target.value)}
            placeholder={`Enter ${p.name.toLowerCase()}`}
          />
        );
    }
  };

  const updateTitle = async (newTitle: string) => {
    if (!task) return;

    console.log("updateTitle - Updating task:", task._id, "with title:", newTitle);

    try {
      const response = await fetch(`/api/todo/tasks/${task._id}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ title: newTitle }),
      });

      if (!response.ok) {
        console.error("updateTitle - API error:", response.status, response.statusText);
        return;
      }

      const updatedTask = await response.json();
      console.log("updateTitle - Successfully updated task:", updatedTask);
      setTask(updatedTask);
    } catch (error) {
      console.error("updateTitle - Fetch error:", error);
    }
  };

  if (!isOpen) return null;

  return (
    <>
      <Dialog
        open={isOpen}
        onOpenChange={(v) => {
          if (!v) {
            console.log("TodoTaskModal - Modal closing, calling onClose and onUpdated");

            if (titleDebounceTimer.current) {
              clearTimeout(titleDebounceTimer.current);
              console.log("TodoTaskModal - Flushing pending title update");
              if (task) {
                updateTitle(localTitle).then(() => {
                  isEditingTitle.current = false;
                });
              }
            } else {
              isEditingTitle.current = false;
            }

            onClose();
            setTimeout(() => {
              onUpdated();
            }, 100);
          }
        }}
      >
        <DialogContent className="max-w-2xl max-h-[90vh] p-0 overflow-hidden">
          <DialogHeader className="px-6 pt-6 pb-4">
            <DialogTitle className="text-xl font-semibold">Task Details</DialogTitle>
          </DialogHeader>

          {loading || !task ? (
            <div className={`p-6 text-sm ${isDark ? "text-gray-400" : "text-gray-500"}`}>
              Loading...
            </div>
          ) : (
            <>
              {/* TITLE */}
              <div className="px-6">
                <input
                  autoFocus
                  value={localTitle}
                  onChange={(e) => {
                    const newValue = e.target.value;
                    console.log("Title onChange triggered:", newValue);

                    isEditingTitle.current = true;
                    setLocalTitle(newValue);

                    if (titleDebounceTimer.current) {
                      clearTimeout(titleDebounceTimer.current);
                    }

                    titleDebounceTimer.current = setTimeout(() => {
                      console.log("Title debounce - Saving to database:", newValue);
                      updateTitle(newValue).then(() => {
                        isEditingTitle.current = false;
                      });
                    }, 500);
                  }}
                  onBlur={() => {
                    isEditingTitle.current = false;
                  }}
                  placeholder="Untitled"
                  className={`w-full text-3xl font-bold outline-none border-b-2 border-transparent pb-2 bg-transparent transition-colors ${
                    isDark
                      ? "hover:border-gray-700 focus:border-blue-500 text-gray-100"
                      : "hover:border-gray-200 focus:border-blue-500 text-gray-900"
                  }`}
                />
              </div>

              <Separator />

              {/* PROPERTIES */}
              <ScrollArea className="max-h-[60vh]">
                <div className="px-6 py-5 space-y-8">
                  {/* Properties header */}
                  <div className="flex items-center justify-between">
                    <div className="text-sm font-semibold uppercase text-muted-foreground">
                      Properties
                    </div>

                    <Button
                      variant="outline"
                      size="sm"
                      onClick={() => {
                        console.log("Add Property button clicked");
                        setShowAddProp(true);
                      }}
                    >
                      + Add Property
                    </Button>
                  </div>

                  {properties.length === 0 && (
                    <div className="py-10 text-center text-muted-foreground">
                      <div>No properties available yet.</div>
                      <div className="text-sm mt-1">
                        Click + Add Property to create fields for your tasks.
                      </div>
                    </div>
                  )}

                  {/* Filled properties */}
                  {filledProps.length > 0 && (
                    <div className="space-y-5">
                      <div className="text-xs font-semibold uppercase tracking-wide text-primary">
                        Filled Properties
                      </div>

                      {filledProps.map((p) => (
                        <div key={p._id} className="space-y-2">
                          <div className="flex items-center gap-2">
                            <Label>{p.name}</Label>
                            <Badge variant="outline" className="text-[10px]">
                              {p.type}
                            </Badge>
                          </div>
                          {renderPropertyInput(p)}
                        </div>
                      ))}
                    </div>
                  )}

                  {/* Empty properties */}
                  {emptyProps.length > 0 && (
                    <div className="space-y-5">
                      <div className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">
                        Empty Properties
                      </div>

                      {emptyProps.map((p) => (
                        <div key={p._id} className="space-y-2 opacity-70">
                          <div className="flex items-center gap-2">
                            <Label className="text-muted-foreground">
                              {p.name}
                            </Label>
                            <Badge variant="outline" className="text-[10px]">
                              {p.type}
                            </Badge>
                          </div>
                          {renderPropertyInput(p)}
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              </ScrollArea>

              <Separator />

              {/* Footer */}
              <div className="flex items-center justify-end gap-2 px-6 py-4">
                <Button variant="outline" onClick={onClose}>
                  Close
                </Button>
              </div>
            </>
          )}
        </DialogContent>
      </Dialog>

      {/* Add Property Modal */}
      {showAddProp && (
        <>
          {console.log("Rendering AddPropertyPicker modal")}
          <AddPropertyPicker
            open={showAddProp}
            properties={properties}
            visiblePropIds={[]}
            databaseId={databaseId}
            onPick={async () => {
              setShowAddProp(false);
              await onUpdated();
            }}
            onPropertyCreated={async () => {
              await onUpdated();
              setShowAddProp(false);
            }}
            onClose={() => setShowAddProp(false)}
          />
        </>
      )}
    </>
  );
}

// components/todo/TodoView.tsx
"use client";

import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import { useTheme } from "next-themes";
import TodoTaskModal from "./TodoTaskModal";
import type { DbView } from "@/components/DatabaseViewtabs";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Separator } from "@/components/ui/separator";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Checkbox } from "@/components/ui/checkbox";
import { Plus } from "lucide-react";

/* ── Types ── */
type Property = { _id:string; databaseId:string; name:string; type:string; options?:string[]; };
type Task     = { _id:string; databaseId:string; title?:string; completed?:boolean; values:Record<string,unknown>; };

/* ── Status config ── */
const STATUS_COLS = [
  { id:"Not started",        dot:"#6b7280", bg_d:"#13151b", bg_l:"#f3f4f6", card_d:"#1c1f28", card_l:"#ffffff" },
  { id:"In progress",        dot:"#3b82f6", bg_d:"#0e1520", bg_l:"#eff6ff", card_d:"#121d2e", card_l:"#ffffff" },
  { id:"Done",               dot:"#10b981", bg_d:"#0c1a12", bg_l:"#ecfdf5", card_d:"#101f15", card_l:"#ffffff" },
  { id:"Blocked",            dot:"#ef4444", bg_d:"#1a0e0e", bg_l:"#fef2f2", card_d:"#220f0f", card_l:"#ffffff" },
];

const PRI_CLS: Record<string, { d:string; l:string }> = {
  High:   { d:"bg-red-950/60     text-red-400     border border-red-800/50",     l:"bg-red-100     text-red-700     border border-red-200"     },
  Medium: { d:"bg-amber-950/60   text-amber-400   border border-amber-800/50",   l:"bg-amber-100   text-amber-700   border border-amber-200"   },
  Low:    { d:"bg-emerald-950/60 text-emerald-400 border border-emerald-800/50", l:"bg-emerald-100 text-emerald-700 border border-emerald-200" },
};

const BAR_GRAD: Record<string,string> = {
  "Not started": "linear-gradient(to right,#0d9488,#10b981)",
  "In progress": "linear-gradient(to right,#3b82f6,#0d9488)",
  "Done":        "linear-gradient(to right,#10b981,#14b8a6)",
  "Blocked":     "linear-gradient(to right,#ef4444,#f97316)",
};

/* ══════════════════════════════════════════════════════════════
   BY STATUS — progress cards kanban (matches screenshot)
══════════════════════════════════════════════════════════════ */
// eslint-disable-next-line @typescript-eslint/no-unused-vars
function ByStatusKanban({ tasks, properties, isDark, onOpenTask }: {
  tasks: Task[]; properties: Property[]; isDark: boolean;
  onOpenTask: (id: string) => void;
}) {
  const statusProp   = properties.find((p) => p.name === "Status");
  const priorityProp = properties.find((p) => p.type === "select" && p.name !== "Status");

  /* group by status value */
  const grouped = useMemo(() => {
    const map: Record<string, Task[]> = {};
    STATUS_COLS.forEach((c) => { map[c.id] = []; });
    tasks.forEach((t) => {
      const s = statusProp ? String(t.values?.[statusProp._id] || "Not started") : "Not started";
      if (!map[s]) map[s] = [];
      map[s].push(t);
    });
    return map;
  }, [tasks, statusProp]);

  /* progress: % of completed tasks in each status group — or read a progress value */
  const getProgress = (t: Task) => {
    const v = t.values && typeof t.values === "object" ? t.values : {};
    /* look for a numeric progress field */
    for (const key of Object.keys(v)) {
      const val = v[key];
      if (typeof val === "number" && val >= 0 && val <= 100) return val;
    }
    /* fallback: completed = 100 */
    return t.completed ? 100 : 0;
  };

  function ProgressCard({ task, col }: { task: Task; col: typeof STATUS_COLS[0] }) {
    const [editProg, setEditProg] = useState(false);
    const [progress, setProgress] = useState(getProgress(task));
    const title    = task.title || "Untitled";
    const priority = priorityProp ? String(task.values?.[priorityProp._id] || "Medium") : "Medium";
    const priCls   = isDark ? (PRI_CLS[priority]?.d || PRI_CLS.Medium.d) : (PRI_CLS[priority]?.l || PRI_CLS.Medium.l);
    const cardBg   = isDark ? col.card_d : col.card_l;
    const barGrad  = BAR_GRAD[col.id] || BAR_GRAD["Not started"];

    return (
      <div
        onClick={() => onOpenTask(task._id)}
        style={{
          background:cardBg,
          border:`1px solid ${isDark?"rgba(255,255,255,0.08)":"rgba(0,0,0,0.07)"}`,
          borderRadius:14, padding:"14px", cursor:"pointer",
          transition:"border-color 0.15s",
        }}
        onMouseEnter={(e)=>(e.currentTarget as HTMLElement).style.borderColor=isDark?"rgba(255,255,255,0.18)":"rgba(0,0,0,0.15)"}
        onMouseLeave={(e)=>(e.currentTarget as HTMLElement).style.borderColor=isDark?"rgba(255,255,255,0.08)":"rgba(0,0,0,0.07)"}
      >
        {/* checkbox + title */}
        <div style={{ display:"flex", alignItems:"flex-start", gap:10, marginBottom:12 }}>
          <input type="checkbox" checked={!!task.completed} readOnly
            onClick={(e)=>e.stopPropagation()}
            style={{ marginTop:2, accentColor:"#0d9488", width:14, height:14, flexShrink:0, cursor:"pointer" }}/>
          <p style={{
            fontSize:13, fontWeight:600, lineHeight:1.45,
            color: isDark?"#f1f5f9":"#111827",
            textDecoration: task.completed ? "line-through" : "none",
            opacity: task.completed ? 0.5 : 1,
          }}>
            {title}
          </p>
        </div>

        {/* progress % */}
        <p style={{ fontSize:11, color:isDark?"#6b7280":"#9ca3af", marginBottom:5, fontVariantNumeric:"tabular-nums" }}>
          {progress}%
        </p>

        {/* progress bar */}
        {editProg ? (
          <input type="range" min={0} max={100} step={5} value={progress} autoFocus
            onClick={(e)=>e.stopPropagation()}
            onChange={(e)=>setProgress(Number(e.target.value))}
            onBlur={()=>setEditProg(false)}
            style={{ width:"100%", marginBottom:10, accentColor:"#0d9488", cursor:"pointer", display:"block" }}/>
        ) : (
          <div
            onClick={(e)=>{e.stopPropagation();setEditProg(true);}}
            title="Click to adjust progress"
            style={{
              width:"100%", height:6, borderRadius:999, marginBottom:10,
              background:isDark?"rgba(255,255,255,0.08)":"#e5e7eb", overflow:"hidden", cursor:"pointer",
            }}
          >
            <div style={{
              height:"100%", borderRadius:999, background:barGrad,
              width:`${progress}%`, minWidth:progress>0?6:0, transition:"width 0.4s",
            }}/>
          </div>
        )}

        {/* priority badge */}
        <span className={`inline-flex items-center px-2.5 py-0.5 rounded-md text-[11px] font-semibold ${priCls}`}>
          {priority}
        </span>
      </div>
    );
  }

  const activeCols = STATUS_COLS.filter((c) => (grouped[c.id]?.length ?? 0) > 0 || true);

  return (
    <div style={{ display:"flex", gap:14, overflowX:"auto", alignItems:"flex-start", padding:"12px 4px 4px" }}>
      {activeCols.map((col) => {
        const colTasks = grouped[col.id] ?? [];
        const colBg    = isDark ? col.bg_d : col.bg_l;
        return (
          <div key={col.id} style={{
            flex:1, minWidth:230, maxWidth:320, background:colBg, borderRadius:18,
            display:"flex", flexDirection:"column",
          }}>
            {/* header */}
            <div style={{ display:"flex", alignItems:"center", gap:8, padding:"13px 14px 10px" }}>
              <span style={{ width:10, height:10, borderRadius:"50%", background:col.dot, flexShrink:0 }}/>
              <span style={{ fontSize:13, fontWeight:700, color:isDark?"#e2e8f0":"#1f2937" }}>{col.id}</span>
              <span style={{
                fontSize:11, fontWeight:700, padding:"1px 7px", borderRadius:999,
                background:isDark?"rgba(255,255,255,0.07)":"rgba(0,0,0,0.06)",
                color:isDark?"#6b7280":"#9ca3af",
              }}>{colTasks.length}</span>
            </div>
            {/* cards */}
            <div style={{ flex:1, overflowY:"auto", padding:"0 10px", minHeight:60 }}>
              <div style={{ display:"flex", flexDirection:"column", gap:9, paddingBottom:8 }}>
                {colTasks.map((t) => <ProgressCard key={t._id} task={t} col={col}/>)}
              </div>
            </div>
          </div>
        );
      })}
    </div>
  );
}

/* ══════════════════════════════════════════════════════════════
   TodoView — main export
══════════════════════════════════════════════════════════════ */
export default function TodoView({
  databaseId, activeViewId, activeView,
}: { databaseId:string; activeViewId?:string; activeView?:DbView; }) {
  const { resolvedTheme } = useTheme();
  const isDark = resolvedTheme === "dark";

  const [properties, setProperties] = useState<Property[]>([]);
  const [tasks,      setTasks]      = useState<Task[]>([]);
  const [loading,    setLoading]    = useState(true);
  const hasSeeded = useRef(false);

  const [open,           setOpen]           = useState(false);
  const [selectedTaskId, setSelectedTaskId] = useState<string|null>(null);
  const quickCreateBusyRef = useRef(false);

  /* ── Fetch ── */
  const fetchAll = useCallback(async () => {
    setLoading(true);
    const [pRes, tRes] = await Promise.all([
      fetch(`/api/todo/properties?databaseId=${databaseId}`),
      fetch(`/api/todo/tasks?databaseId=${databaseId}`),
    ]);
    setProperties(await pRes.json());
    setTasks(await tRes.json());
    setLoading(false);
  }, [databaseId]);

  useEffect(() => { hasSeeded.current = false; }, [databaseId]);
  useEffect(() => { fetchAll(); }, [fetchAll]);

  const titleProp     = useMemo(() => properties.find((p)=>p.type==="title"),    [properties]);
  const completedProp = useMemo(() => properties.find((p)=>p.type==="checkbox"), [properties]);
  const dueDateProp   = useMemo(() => properties.find((p)=>p.type==="date"),     [properties]);
  const statusProp    = useMemo(() => properties.find((p)=>p.name==="Status"),   [properties]);
  const assigneeProp  = useMemo(() => properties.find((p)=>p.type==="person"),   [properties]);

  /* ── Seed defaults ── */
  useEffect(() => {
    const seed = async () => {
      if (!databaseId || hasSeeded.current || loading || properties.length > 0) {
        hasSeeded.current = true; return;
      }
      hasSeeded.current = true;
      const defaults = [
        { name:"Name",      type:"title" },
        { name:"Completed", type:"checkbox" },
        { name:"Due date",  type:"date" },
        { name:"Status",    type:"select", options:["Not started","In progress","Done","Blocked"] },
        { name:"Assignee",  type:"person" },
        { name:"Priority",  type:"select", options:["Low","Medium","High"] },
      ];
      await Promise.all(defaults.map((p) =>
        fetch("/api/todo/properties", {
          method:"POST", headers:{"Content-Type":"application/json"},
          body: JSON.stringify({ databaseId, ...p }),
        })
      ));
      fetchAll();
    };
    seed();
  }, [databaseId, loading, properties.length, fetchAll]);

  /* ── Create task ── */
  const createTask = async () => {
    const values: Record<string,unknown> = {};
    if (titleProp)     values[titleProp._id]     = "";
    if (completedProp) values[completedProp._id] = false;
    const res     = await fetch("/api/todo/tasks", {
      method:"POST", headers:{"Content-Type":"application/json"},
      body: JSON.stringify({ databaseId, title:"New task", values }),
    });
    const created = await res.json();
    setTasks((prev) => [created, ...prev]);
    setSelectedTaskId(created._id); setOpen(true);
  };

  const handleQuickCreate = async () => {
    if (quickCreateBusyRef.current) return;
    quickCreateBusyRef.current = true;
    try {
      await createTask();
    } finally {
      quickCreateBusyRef.current = false;
    }
  };

  const toggleCompleted = async (task: Task) => {
    const newCompleted = !task.completed;
    setTasks((prev) => prev.map((t) => t._id===task._id ? {...t,completed:newCompleted} : t));
    await fetch(`/api/todo/tasks/${task._id}`, {
      method:"PATCH", headers:{"Content-Type":"application/json"},
      body: JSON.stringify({ completed: newCompleted }),
    });
  };

  /* ── Filtered tasks by view ── */
  const filteredTasks = useMemo(() => {
    if (!activeView || activeView.type === "all") return tasks;
    if (activeView.type === "my-tasks") {
      return tasks.filter((t) => {
        const a = assigneeProp ? t.values?.[assigneeProp._id] : null;
        return a === "me" || a === "You";
      });
    }
    return tasks; // by-status handled in ByStatusKanban
  }, [tasks, activeView, assigneeProp]);

  if (loading) return <div className="p-6 text-sm text-gray-400">Loading…</div>;

  /* ── BY STATUS → progress kanban ── */
  if (activeView?.type === "by-status") {
    return (
      <>
        <div className="p-3 space-y-3">
          <input
            readOnly
            value=""
            placeholder="Create task..."
            aria-label="Create task"
            title="Create task"
            onClick={handleQuickCreate}
            className={`w-full rounded-lg border px-3 py-2 text-sm outline-none transition-colors ${
              isDark
                ? "border-gray-700 bg-[#111317] text-gray-200 placeholder:text-gray-400 hover:bg-[#1a1d23]"
                : "border-gray-200 bg-white text-gray-900 placeholder:text-gray-500 hover:bg-gray-50"
            }`}
          />
        </div>

        <TodoTaskModal
          isOpen={open}
          onClose={() => setOpen(false)}
          databaseId={databaseId}
          taskId={selectedTaskId}
          properties={properties}
          onUpdated={fetchAll}
        />
      </>
    );
  }

  /* ── MY TASKS → flat filtered list with progress ── */
  if (activeView?.type === "my-tasks") {
    return (
      <>
        <div className="p-4 space-y-2">
          {filteredTasks.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-12 text-sm text-gray-500">
              <span className="text-4xl mb-3 opacity-30">🎯</span>
              No tasks assigned to you.
            </div>
          ) : filteredTasks.map((task) => {
            const title    = task.title || "Untitled";
            const done     = task.completed || false;
            const progress = done ? 100 : 0;
            const priProp  = properties.find((p)=>p.name==="Priority");
            const priority = priProp ? String(task.values?.[priProp._id]||"Medium") : "Medium";
            const priCls   = isDark ? (PRI_CLS[priority]?.d||PRI_CLS.Medium.d) : (PRI_CLS[priority]?.l||PRI_CLS.Medium.l);
            return (
              <div key={task._id}
                style={{
                  background:isDark?"#1c1f28":"#ffffff",
                  border:`1px solid ${isDark?"rgba(255,255,255,0.08)":"rgba(0,0,0,0.07)"}`,
                  borderRadius:14, padding:"14px", cursor:"pointer",
                }}
                onClick={()=>{ setSelectedTaskId(task._id); setOpen(true); }}
              >
                <div style={{ display:"flex", alignItems:"flex-start", gap:10, marginBottom:10 }}>
                  <input type="checkbox" checked={!!done}
                    onClick={(e)=>{ e.stopPropagation(); toggleCompleted(task); }}
                    readOnly style={{ marginTop:2, width:14, height:14, accentColor:"#0d9488", cursor:"pointer", flexShrink:0 }}/>
                  <p style={{ fontSize:13, fontWeight:600, color:isDark?"#f1f5f9":"#111827",
                    textDecoration:done?"line-through":"none", opacity:done?0.5:1, lineHeight:1.4 }}>
                    {title}
                  </p>
                </div>
                <p style={{ fontSize:11, color:isDark?"#6b7280":"#9ca3af", marginBottom:5 }}>{progress}%</p>
                <div style={{ width:"100%", height:6, borderRadius:999, marginBottom:10,
                  background:isDark?"rgba(255,255,255,0.08)":"#e5e7eb", overflow:"hidden" }}>
                  <div style={{ height:"100%", borderRadius:999, width:`${progress}%`,
                    background:"linear-gradient(to right,#0d9488,#10b981)", transition:"width 0.4s" }}/>
                </div>
                <span className={`inline-flex items-center px-2.5 py-0.5 rounded-md text-[11px] font-semibold ${priCls}`}>
                  {priority}
                </span>
              </div>
            );
          })}
        </div>
        <TodoTaskModal isOpen={open} onClose={()=>setOpen(false)}
          databaseId={databaseId} taskId={selectedTaskId}
          properties={properties} onUpdated={fetchAll}/>
      </>
    );
  }

  /* ── ALL TASKS → original checkbox list ── */
  return (
    <>
      <Card className={`${isDark?"bg-transparent border-white":"bg-gray-50"} rounded-xl border overflow-hidden`}>
        <CardHeader className="flex flex-row items-center justify-between">
          <CardTitle>To-do</CardTitle>
          <Button onClick={createTask} size="sm"><Plus className="mr-2 h-4 w-4"/>New</Button>
        </CardHeader>
        <Separator/>
        <CardContent className="p-0">
          <ScrollArea className="h-[360px]">
            <div className="p-4 space-y-2">
              {filteredTasks.map((task) => {
                const title   = task.title || "";
                const done    = task.completed || false;
                const dueDate = dueDateProp ? task.values?.[dueDateProp._id] : "";
                return (
                  <div key={task._id}
                    className={`flex items-center border gap-3 px-3 py-2 rounded-md ${
                      isDark?"bg-transparent border-white hover:bg-gray-600":"bg-rose-50 hover:bg-rose-100"
                    } hover:text-gray-800 dark:hover:text-gray-100`}>
                    <Checkbox checked={!!done} onCheckedChange={()=>toggleCompleted(task)}/>
                    <button onClick={()=>{ setSelectedTaskId(task._id); setOpen(true); }} className="flex-1 text-left">
                      <div className={["text-sm font-medium", done?"line-through text-muted-foreground":"", !title?"text-gray-400 italic":""].join(" ")}>
                        {title || "New task"}
                      </div>
                    </button>
                    {dueDateProp && (
                      <div className="flex items-center gap-2 text-xs text-gray-500 min-w-[120px]">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z"/>
                        </svg>
                        {dueDate ? new Date(dueDate as string).toLocaleDateString() : "No date"}
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          </ScrollArea>
        </CardContent>
      </Card>
      <TodoTaskModal isOpen={open} onClose={()=>setOpen(false)}
        databaseId={databaseId} taskId={selectedTaskId}
        properties={properties} onUpdated={fetchAll}/>
    </>
  );
}

"use client";

import { useState, useRef, useEffect, useCallback } from "react";
import {
  Plus, Trash2, Download, Volume2, VolumeX, Maximize,
  Type, RotateCcw, FastForward, Rewind, Play, Pause,
  SkipBack, SkipForward, Film, Palette, Sliders, Music,
  Upload, Scissors, Copy, MoveVertical, Sun, Contrast,
  FlipHorizontal, FlipVertical, RotateCw, ZoomIn,
} from "lucide-react";

// ── Types ──────────────────────────────────────────────────────────
interface TextOverlay {
  id: string; text: string; startTime: number; endTime: number;
  x: number; y: number; fontSize: number; color: string; bgColor: string;
  bold: boolean; italic: boolean; fontFamily: string;
}

interface Clip {
  id: string; title: string; url: string; localFile?: boolean;
  startTrim: number; endTrim: number | null;
  volume: number; playbackRate: number;
  brightness: number; contrast: number; saturation: number;
  hue: number; blur: number; sepia: number; grayscale: number;
  sharpness: number; vignette: number; temperature: number;
  flipH: boolean; flipV: boolean; rotate: number; opacity: number;
  textOverlays: TextOverlay[]; addedAt: string;
}

const makeClip = (o: Partial<Clip> & { url: string; title: string }): Clip => ({
  id: Date.now().toString() + Math.random().toString(36).slice(2),
  startTrim: 0, endTrim: null, volume: 1, playbackRate: 1,
  brightness: 100, contrast: 100, saturation: 100, hue: 0,
  blur: 0, sepia: 0, grayscale: 0, sharpness: 0, vignette: 0, temperature: 0,
  flipH: false, flipV: false, rotate: 0, opacity: 100,
  textOverlays: [], addedAt: new Date().toISOString(), ...o,
});

// ── Constants ──────────────────────────────────────────────────────
const PLAYBACK_RATES = [0.25, 0.5, 0.75, 1, 1.25, 1.5, 1.75, 2, 3, 4];

const FILTER_PRESETS = [
  { name:"None",      brightness:100,contrast:100,saturation:100,hue:0,  sepia:0, grayscale:0  },
  { name:"Vivid",     brightness:110,contrast:120,saturation:150,hue:0,  sepia:0, grayscale:0  },
  { name:"Muted",     brightness:95, contrast:90, saturation:60, hue:0,  sepia:0, grayscale:0  },
  { name:"Vintage",   brightness:100,contrast:90, saturation:80, hue:0,  sepia:40,grayscale:0  },
  { name:"B&W",       brightness:100,contrast:110,saturation:0,  hue:0,  sepia:0, grayscale:100},
  { name:"Warm",      brightness:105,contrast:100,saturation:110,hue:10, sepia:20,grayscale:0  },
  { name:"Cool",      brightness:95, contrast:100,saturation:90, hue:200,sepia:0, grayscale:0  },
  { name:"Dramatic",  brightness:90, contrast:150,saturation:80, hue:0,  sepia:0, grayscale:0  },
  { name:"Fade",      brightness:110,contrast:80, saturation:70, hue:0,  sepia:10,grayscale:0  },
  { name:"Cinematic", brightness:95, contrast:130,saturation:85, hue:5,  sepia:15,grayscale:0  },
  { name:"Summer",    brightness:110,contrast:105,saturation:130,hue:15, sepia:10,grayscale:0  },
  { name:"Noir",      brightness:85, contrast:140,saturation:0,  hue:0,  sepia:30,grayscale:80 },
];

const FONTS = ["Arial","Georgia","Impact","Courier New","Trebuchet MS","Comic Sans MS","Verdana","Helvetica"];
const ACCEPTED_VIDEO_TYPES = "video/mp4,video/webm,video/ogg,video/mov,video/avi,video/mkv,video/*";

// ── Main Component ─────────────────────────────────────────────────
export default function VideoView({ databaseId }: { databaseId: string }) {
  const [clips, setClips]               = useState<Clip[]>([makeClip({ title:"Sample Video", url:"https://www.w3schools.com/html/mov_bbb.mp4" })]);
  const [selectedClip, setSelectedClip] = useState<Clip>(clips[0]);
  const [isPlaying, setIsPlaying]       = useState(false);
  const [progress, setProgress]         = useState(0);
  const [currentTime, setCurrentTime]   = useState(0);
  const [duration, setDuration]         = useState(0);
  const [activePanel, setActivePanel]   = useState<"clips"|"filter"|"adjust"|"text"|"audio"|"speed"|"transform"|"crop">("clips");
  const [showAddModal, setShowAddModal] = useState(false);
  const [addTab, setAddTab]             = useState<"url"|"upload">("upload");
  const [newUrl, setNewUrl]             = useState("");
  const [newTitle, setNewTitle]         = useState("");
  const [urlError, setUrlError]         = useState("");
  const [isDraggingFile, setIsDraggingFile] = useState(false);

  // Text overlay state
  const [overlayText, setOverlayText]   = useState("");
  const [overlayColor, setOverlayColor] = useState("#ffffff");
  const [overlayBg, setOverlayBg]       = useState("transparent");
  const [overlayFontSize, setOverlayFontSize] = useState(24);
  const [overlayFont, setOverlayFont]   = useState("Arial");
  const [overlayBold, setOverlayBold]   = useState(false);
  const [overlayItalic, setOverlayItalic] = useState(false);
  const [overlayX, setOverlayX]         = useState(50);
  const [overlayY, setOverlayY]         = useState(80);
  const [editingOverlayId, setEditingOverlayId] = useState<string|null>(null);

  // Crop state
  const [cropMode, setCropMode]         = useState(false);
  const [cropAspect, setCropAspect]     = useState("free");

  // Save state
  const [loadedOnce, setLoadedOnce]     = useState(false);
  const [saving, setSaving]             = useState(false);
  const [savedAt, setSavedAt]           = useState<string|null>(null);

  const videoRef     = useRef<HTMLVideoElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const uploadDropRef = useRef<HTMLDivElement>(null);
  const sel = selectedClip;

  // ── Load from DB ──
  useEffect(() => {
    const load = async () => {
      try {
        const res  = await fetch(`/api/databases/${databaseId}/video`);
        const json = await res.json();
        if (json.clips?.length) {
          // Filter out any local blob URLs (they won't survive refresh)
          const restored = json.clips.map((c: Clip) => ({
            ...c,
            url: c.localFile ? "" : c.url,
          }));
          setClips(restored);
          setSelectedClip(restored[0]);
        }
      } catch (e) { console.error("Load failed:", e); }
      finally { setLoadedOnce(true); }
    };
    load();
  }, [databaseId]);

  // ── Auto-save ──
  useEffect(() => {
    if (!loadedOnce) return;
    const t = setTimeout(async () => {
      setSaving(true);
      try {
        // Don't save blob URLs (they're session-only)
        const saveable = clips.map(c => ({
          ...c,
          url: c.localFile ? "" : c.url,
        }));
        await fetch(`/api/databases/${databaseId}/video`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ clips: saveable }),
        });
        setSavedAt(new Date().toLocaleTimeString());
      } catch {}
      finally { setSaving(false); }
    }, 3000);
    return () => clearTimeout(t);
  }, [clips, databaseId, loadedOnce]);

  // ── Sync video props ──
  useEffect(() => {
    const v = videoRef.current;
    if (!v) return;
    v.volume = sel.volume;
    v.playbackRate = sel.playbackRate;
  }, [sel.volume, sel.playbackRate, selectedClip.id]);

  // ── Handlers ──
  const updateClip = useCallback((updates: Partial<Clip>) => {
    setClips(prev => prev.map(c => c.id === sel.id ? { ...c, ...updates } : c));
    setSelectedClip(prev => ({ ...prev, ...updates }));
  }, [sel.id]);

  const handleTimeUpdate = () => {
    const v = videoRef.current;
    if (!v) return;
    setCurrentTime(v.currentTime);
    setProgress((v.currentTime / v.duration) * 100 || 0);
    if (sel.endTrim && v.currentTime >= sel.endTrim) { v.pause(); setIsPlaying(false); }
  };

  const handleLoaded = () => {
    const v = videoRef.current;
    if (!v) return;
    setDuration(v.duration);
    if (sel.startTrim > 0) v.currentTime = sel.startTrim;
  };

  const togglePlay = () => {
    const v = videoRef.current;
    if (!v || !sel.url) return;
    if (isPlaying) v.pause(); else v.play().catch(() => {});
    setIsPlaying(!isPlaying);
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const v = videoRef.current;
    if (!v) return;
    v.currentTime = (Number(e.target.value) / 100) * duration;
    setProgress(Number(e.target.value));
  };

  const fmt = (s: number) => `${Math.floor(s / 60)}:${String(Math.floor(s % 60)).padStart(2, "0")}`;

  const getFilter = (c: Clip) =>
    `brightness(${c.brightness}%) contrast(${c.contrast}%) saturate(${c.saturation}%) hue-rotate(${c.hue}deg) blur(${c.blur}px) sepia(${c.sepia}%) grayscale(${c.grayscale}%)`;

  const getTransform = (c: Clip) =>
    `scaleX(${c.flipH ? -1 : 1}) scaleY(${c.flipV ? -1 : 1}) rotate(${c.rotate}deg)`;

  // ── Add from URL ──
  const addFromUrl = () => {
    if (!newUrl.trim()) { setUrlError("Enter a URL"); return; }
    const c = makeClip({ title: newTitle || "Untitled", url: newUrl });
    setClips(p => [...p, c]);
    setSelectedClip(c);
    setNewUrl(""); setNewTitle(""); setUrlError(""); setShowAddModal(false);
    setIsPlaying(false);
  };

  // ── Add from desktop file ──
  const addFromFile = useCallback((file: File) => {
    if (!file.type.startsWith("video/")) { alert("Please select a video file."); return; }
    const url = URL.createObjectURL(file);
    const title = file.name.replace(/\.[^/.]+$/, ""); // strip extension
    const c = makeClip({ title, url, localFile: true });
    setClips(p => [...p, c]);
    setSelectedClip(c);
    setShowAddModal(false);
    setIsPlaying(false);
  }, []);

  const handleFileInput = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) addFromFile(file);
    e.target.value = "";
  };

  // ── Drag & drop file onto modal ──
  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDraggingFile(false);
    const file = e.dataTransfer.files[0];
    if (file) addFromFile(file);
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDraggingFile(true);
  };

  const handleDragLeave = () => setIsDraggingFile(false);

  // ── Clip ops ──
  const deleteClip = (id: string) => {
    const clip = clips.find(c => c.id === id);
    if (clip?.localFile && clip.url) URL.revokeObjectURL(clip.url); // free memory
    const remaining = clips.filter(c => c.id !== id);
    setClips(remaining);
    if (selectedClip.id === id && remaining.length > 0) setSelectedClip(remaining[0]);
  };

  const duplicateClip = (id: string) => {
    const clip = clips.find(c => c.id === id);
    if (!clip) return;
    const newClip = { ...clip, id: Date.now().toString(), title: clip.title + " (copy)" };
    setClips(p => [...p, newClip]);
  };

  const reorderClip = (id: string, dir: "up" | "down") => {
    const idx = clips.findIndex(c => c.id === id);
    if (dir === "up" && idx === 0) return;
    if (dir === "down" && idx === clips.length - 1) return;
    const arr = [...clips];
    const swap = dir === "up" ? idx - 1 : idx + 1;
    [arr[idx], arr[swap]] = [arr[swap], arr[idx]];
    setClips(arr);
  };

  // ── Text overlays ──
  const addTextOverlay = () => {
    if (!overlayText.trim()) return;
    const ov: TextOverlay = {
      id: Date.now().toString(), text: overlayText,
      startTime: currentTime, endTime: currentTime + 5,
      x: overlayX, y: overlayY, fontSize: overlayFontSize,
      color: overlayColor, bgColor: overlayBg,
      bold: overlayBold, italic: overlayItalic, fontFamily: overlayFont,
    };
    updateClip({ textOverlays: [...sel.textOverlays, ov] });
    setOverlayText("");
  };

  const updateOverlay = (id: string, updates: Partial<TextOverlay>) => {
    updateClip({
      textOverlays: sel.textOverlays.map(o => o.id === id ? { ...o, ...updates } : o),
    });
  };

  const removeOverlay = (id: string) =>
    updateClip({ textOverlays: sel.textOverlays.filter(o => o.id !== id) });

  const activeOverlays = sel.textOverlays.filter(
    o => currentTime >= o.startTime && currentTime <= o.endTime
  );

  // ── Export ──
  const handleExport = () => {
    if (!sel.url || sel.localFile) {
      alert("Local file export: use your browser's built-in tools or a screen recorder.\n\nFor URL-based clips, the file will download.");
      return;
    }
    const a = document.createElement("a");
    a.href = sel.url; a.download = sel.title; a.click();
  };

  const handleSnapshot = () => {
    const v = videoRef.current;
    if (!v) return;
    const canvas = document.createElement("canvas");
    canvas.width = v.videoWidth; canvas.height = v.videoHeight;
    const ctx = canvas.getContext("2d");
    if (!ctx) return;
    ctx.filter = getFilter(sel);
    ctx.drawImage(v, 0, 0);
    const a = document.createElement("a");
    a.href = canvas.toDataURL("image/png");
    a.download = `snapshot-${Date.now()}.png`;
    a.click();
  };

  // ── Components ──
  const PanelBtn = ({ id, icon, label }: { id: typeof activePanel; icon: React.ReactNode; label: string }) => (
    <button onClick={() => setActivePanel(id)}
      className={`flex flex-col items-center gap-0.5 px-2.5 py-1.5 rounded-lg text-[9px] font-medium transition whitespace-nowrap ${activePanel === id ? "bg-indigo-600 text-white" : "text-gray-400 hover:bg-gray-700 hover:text-white"}`}>
      {icon}{label}
    </button>
  );

  const Slider = ({ label, value, min, max, step = 1, onChange, onReset, unit = "" }:
    { label: string; value: number; min: number; max: number; step?: number; onChange: (v: number) => void; onReset?: () => void; unit?: string }) => (
    <div className="flex items-center gap-2">
      <span className="text-[9px] text-gray-400 w-18 shrink-0 leading-tight">{label}</span>
      <input type="range" min={min} max={max} step={step} value={value}
        onChange={e => onChange(Number(e.target.value))}
        className="flex-1 h-1 accent-indigo-500 cursor-pointer"/>
      <span className="text-[9px] text-gray-400 w-10 text-right">{value}{unit}</span>
      {onReset && (
        <button onClick={onReset} title="Reset" className="text-gray-600 hover:text-gray-400 transition shrink-0">
          <RotateCcw size={9}/>
        </button>
      )}
    </div>
  );

  return (
    <div className="flex flex-col h-full bg-gray-950 text-white overflow-hidden rounded-2xl">

      {/* ══ TOP BAR ══ */}
      <div className="flex items-center justify-between px-3 py-1.5 bg-gray-900 border-b border-gray-800 shrink-0">
        <div className="flex items-center gap-2">
          <span className="text-xs font-semibold">🎥 Video Editor</span>
          {saving && <span className="text-[9px] text-amber-400 animate-pulse">● Saving</span>}
          {!saving && savedAt && <span className="text-[9px] text-emerald-400">✓ {savedAt}</span>}
          {sel.localFile && <span className="text-[9px] text-blue-400 bg-blue-400/10 border border-blue-400/20 px-2 py-0.5 rounded-full">Local file</span>}
        </div>
        <div className="flex items-center gap-1">
          <button onClick={handleSnapshot} title="Snapshot current frame"
            className="flex items-center gap-1 px-2 py-1 bg-gray-700 hover:bg-gray-600 text-white text-xs rounded-lg transition">
            📸 Snapshot
          </button>
          <button onClick={handleExport}
            className="flex items-center gap-1 px-2 py-1 bg-gray-700 hover:bg-gray-600 text-white text-xs rounded-lg transition">
            <Download size={12}/> Export
          </button>
          <button onClick={() => setShowAddModal(true)}
            className="flex items-center gap-1 px-2 py-1 bg-indigo-600 hover:bg-indigo-500 text-white text-xs rounded-lg transition">
            <Plus size={12}/> Add Clip
          </button>
        </div>
      </div>

      <div className="flex flex-1 overflow-hidden">

        {/* ══ LEFT: Clip list ══ */}
        <div className="w-48 bg-gray-900 border-r border-gray-800 flex flex-col shrink-0">
          <div className="flex items-center justify-between px-3 py-2 border-b border-gray-800">
            <p className="text-[10px] font-semibold text-gray-400 uppercase tracking-wider">Clips ({clips.length})</p>
            {/* Quick upload button */}
            <label title="Upload from desktop" className="cursor-pointer p-1 rounded hover:bg-gray-700 text-gray-400 hover:text-white transition">
              <Upload size={12}/>
              <input type="file" accept={ACCEPTED_VIDEO_TYPES} className="hidden" onChange={handleFileInput}/>
            </label>
          </div>
          <div className="flex-1 overflow-y-auto">
            {clips.length === 0 && (
              <div className="flex flex-col items-center justify-center h-32 gap-2 text-gray-600">
                <Film size={20}/>
                <p className="text-[10px] text-center px-4">No clips yet.<br/>Click + Add Clip</p>
              </div>
            )}
            {clips.map((c, idx) => (
              <div key={c.id}
                onClick={() => { setSelectedClip(c); setIsPlaying(false); }}
                className={`flex items-center gap-2 px-2 py-2 cursor-pointer hover:bg-gray-800 transition border-b border-gray-800 group ${selectedClip.id === c.id ? "bg-gray-800 border-l-2 border-l-indigo-500" : ""}`}>
                <div className="w-10 h-8 bg-gray-700 rounded flex items-center justify-center text-sm shrink-0 relative">
                  🎬
                  {c.localFile && (
                    <div className="absolute -top-1 -right-1 w-3 h-3 bg-blue-500 rounded-full flex items-center justify-center">
                      <Upload size={7}/>
                    </div>
                  )}
                </div>
                <div className="flex-1 min-w-0">
                  <p className="text-[10px] font-medium truncate">{c.title}</p>
                  <p className="text-[9px] text-gray-500">{fmt(c.startTrim)} → {c.endTrim ? fmt(c.endTrim) : "end"}</p>
                </div>
                <div className="flex flex-col gap-0.5 opacity-0 group-hover:opacity-100 transition shrink-0">
                  <button onClick={e => { e.stopPropagation(); duplicateClip(c.id); }} className="p-0.5 bg-blue-600 rounded text-white" title="Duplicate"><Copy size={8}/></button>
                  <button onClick={e => { e.stopPropagation(); deleteClip(c.id); }} className="p-0.5 bg-red-600 rounded text-white" title="Delete"><Trash2 size={8}/></button>
                </div>
              </div>
            ))}
          </div>

          {/* Drop zone in sidebar */}
          <div
            className="m-2 rounded-xl border-2 border-dashed border-gray-700 hover:border-indigo-500 transition cursor-pointer p-3 text-center"
            onClick={() => fileInputRef.current?.click()}
            onDrop={e => { e.preventDefault(); const f=e.dataTransfer.files[0]; if(f) addFromFile(f); }}
            onDragOver={e => e.preventDefault()}
          >
            <Upload size={14} className="mx-auto mb-1 text-gray-500"/>
            <p className="text-[9px] text-gray-500 leading-tight">Drop video here<br/>or click to browse</p>
            <input ref={fileInputRef} type="file" accept={ACCEPTED_VIDEO_TYPES} className="hidden" onChange={handleFileInput}/>
          </div>
        </div>

        {/* ══ CENTER: Video preview ══ */}
        <div className="flex-1 flex flex-col overflow-hidden min-w-0">

          {/* Video */}
          <div className="flex-1 bg-black flex items-center justify-center relative overflow-hidden">
            {sel.url ? (
              <>
                <video ref={videoRef} src={sel.url} crossOrigin="anonymous"
  className="max-h-full max-w-full"
  style={{
    filter: getFilter(sel),
    transform: getTransform(sel),
    opacity: sel.opacity / 100,
  }}
  onTimeUpdate={handleTimeUpdate}
  onLoadedMetadata={handleLoaded}
  onEnded={() => setIsPlaying(false)}
  onClick={togglePlay}
/>

                {/* Vignette overlay */}
                {sel.vignette > 0 && (
                  <div className="absolute inset-0 pointer-events-none"
                    style={{ boxShadow: `inset 0 0 ${sel.vignette * 3}px ${sel.vignette * 2}px rgba(0,0,0,0.8)` }}/>
                )}

                {/* Text overlays */}
                {activeOverlays.map(o => (
                  <div key={o.id} className="absolute pointer-events-none px-2 py-1 rounded select-none"
                    style={{
                      left: `${o.x}%`, top: `${o.y}%`, transform: "translate(-50%,-50%)",
                      fontSize: o.fontSize, color: o.color,
                      backgroundColor: o.bgColor === "transparent" ? "rgba(0,0,0,0)" : o.bgColor,
                      fontFamily: o.fontFamily,
                      fontWeight: o.bold ? "bold" : "normal",
                      fontStyle: o.italic ? "italic" : "normal",
                      textShadow: "0 1px 4px rgba(0,0,0,0.8)",
                    }}>
                    {o.text}
                  </div>
                ))}

                {/* Play overlay */}
                {!isPlaying && (
                  <div onClick={togglePlay} className="absolute inset-0 flex items-center justify-center cursor-pointer">
                    <div className="w-14 h-14 bg-black/60 rounded-full flex items-center justify-center hover:bg-black/80 transition">
                      <Play size={24} className="ml-0.5"/>
                    </div>
                  </div>
                )}

                {/* Crop overlay hint */}
                {cropMode && (
                  <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                    <div className="border-2 border-dashed border-yellow-400 w-3/4 h-3/4 rounded"/>
                    <div className="absolute bg-yellow-400/20 inset-0"/>
                  </div>
                )}
              </>
            ) : (
              // Empty state — drop target
              <div
                className="flex flex-col items-center justify-center gap-3 text-gray-600 w-full h-full"
                onDrop={e => { e.preventDefault(); const f=e.dataTransfer.files[0]; if(f) addFromFile(f); }}
                onDragOver={e => e.preventDefault()}
              >
                <Film size={40} className="opacity-30"/>
                <p className="text-sm text-gray-500">No video loaded</p>
                <p className="text-[11px] text-gray-600">Drop a video file here, or use the sidebar</p>
                <label className="px-4 py-2 bg-indigo-600 hover:bg-indigo-500 text-white text-xs rounded-lg cursor-pointer transition flex items-center gap-2">
                  <Upload size={14}/> Upload Video
                  <input type="file" accept={ACCEPTED_VIDEO_TYPES} className="hidden" onChange={handleFileInput}/>
                </label>
              </div>
            )}
          </div>

          {/* ── Timeline + Controls ── */}
          <div className="bg-gray-900 border-t border-gray-800 px-4 py-2 shrink-0">
            {/* Progress / timeline */}
            <div className="relative mb-2">
              <div className="relative h-8 bg-gray-800 rounded-lg overflow-hidden cursor-pointer">
                {/* Trim zone */}
                <div className="absolute h-full bg-indigo-900/40 border-x-2 border-indigo-500"
                  style={{
                    left: `${(sel.startTrim / duration) * 100 || 0}%`,
                    right: `${100 - ((sel.endTrim || duration) / duration) * 100 || 0}%`,
                  }}/>
                {/* Progress fill */}
                <div className="absolute left-0 top-0 h-full bg-indigo-600/20 transition-all"
                  style={{ width: `${progress}%` }}/>
                {/* Playhead */}
                <div className="absolute top-0 bottom-0 w-0.5 bg-white shadow-sm"
                  style={{ left: `${progress}%` }}/>
                {/* Text overlay markers */}
                {sel.textOverlays.map(o => (
                  <div key={o.id} className="absolute top-0 h-1.5 bg-yellow-400 opacity-70 rounded-sm"
                    style={{
                      left: `${(o.startTime / duration) * 100}%`,
                      width: `${((o.endTime - o.startTime) / duration) * 100}%`,
                    }}/>
                ))}
                <input type="range" min={0} max={100} step={0.1} value={progress}
                  onChange={handleSeek}
                  className="absolute inset-0 w-full opacity-0 cursor-pointer h-full"/>
              </div>
              <div className="flex justify-between text-[9px] text-gray-500 mt-0.5 px-0.5">
                <span>{fmt(currentTime)}</span>
                <span className="text-gray-600">{sel.startTrim > 0 ? `Trim: ${fmt(sel.startTrim)} → ${sel.endTrim ? fmt(sel.endTrim) : fmt(duration)}` : ""}</span>
                <span>{fmt(duration)}</span>
              </div>
            </div>

            {/* Playback controls */}
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-2">
                <button onClick={() => { if (videoRef.current) videoRef.current.currentTime = sel.startTrim; }}
                  className="text-gray-400 hover:text-white transition" title="Go to start"><SkipBack size={14}/></button>
                <button onClick={() => { if (videoRef.current) videoRef.current.currentTime = Math.max(0, currentTime - 5); }}
                  className="text-gray-400 hover:text-white transition" title="Back 5s"><Rewind size={14}/></button>
                <button onClick={togglePlay} title={isPlaying ? "Pause" : "Play"}
                  className="w-8 h-8 bg-indigo-600 hover:bg-indigo-500 rounded-full flex items-center justify-center transition">
                  {isPlaying ? <Pause size={14}/> : <Play size={14} className="ml-0.5"/>}
                </button>
                <button onClick={() => { if (videoRef.current) videoRef.current.currentTime = Math.min(duration, currentTime + 5); }}
                  className="text-gray-400 hover:text-white transition" title="Forward 5s"><FastForward size={14}/></button>
                <button onClick={() => { if (videoRef.current) videoRef.current.currentTime = sel.endTrim || duration; }}
                  className="text-gray-400 hover:text-white transition" title="Go to end"><SkipForward size={14}/></button>
              </div>

              <div className="flex items-center gap-2">
                {/* Volume */}
                <button onClick={() => updateClip({ volume: sel.volume > 0 ? 0 : 1 })}
                  className="text-gray-400 hover:text-white transition">
                  {sel.volume === 0 ? <VolumeX size={14}/> : <Volume2 size={14}/>}
                </button>
                <input type="range" min={0} max={1} step={0.05} value={sel.volume}
                  onChange={e => updateClip({ volume: Number(e.target.value) })}
                  className="w-16 h-1 accent-indigo-500 cursor-pointer"/>
                <span className="text-[9px] text-gray-400 w-6">{Math.round(sel.volume * 100)}%</span>

                {/* Speed */}
                <select value={sel.playbackRate}
                  onChange={e => updateClip({ playbackRate: Number(e.target.value) })}
                  className="h-5 text-[9px] bg-gray-800 border border-gray-700 text-white rounded px-1 focus:outline-none">
                  {PLAYBACK_RATES.map(r => <option key={r} value={r}>{r}x</option>)}
                </select>

                {/* Fullscreen */}
                <button onClick={() => videoRef.current?.requestFullscreen()}
                  className="text-gray-400 hover:text-white transition"><Maximize size={14}/></button>
              </div>
            </div>
          </div>

          {/* ── Panel Tabs ── */}
          <div className="flex items-center gap-0.5 px-2 py-1.5 bg-gray-900 border-t border-gray-800 shrink-0 overflow-x-auto">
            <PanelBtn id="clips"     icon={<Film size={12}/>}            label="Clips"/>
            <PanelBtn id="filter"    icon={<Palette size={12}/>}         label="Filter"/>
            <PanelBtn id="adjust"    icon={<Sliders size={12}/>}         label="Adjust"/>
            <PanelBtn id="transform" icon={<FlipHorizontal size={12}/>}  label="Transform"/>
            <PanelBtn id="text"      icon={<Type size={12}/>}            label="Text"/>
            <PanelBtn id="audio"     icon={<Music size={12}/>}           label="Audio"/>
            <PanelBtn id="speed"     icon={<FastForward size={12}/>}     label="Speed"/>
            <PanelBtn id="crop"      icon={<Scissors size={12}/>}        label="Trim"/>
          </div>
        </div>

        {/* ══ RIGHT: Tool Panels ══ */}
        <div className="w-64 bg-gray-900 border-l border-gray-800 overflow-y-auto shrink-0 p-3 space-y-4">

          {/* ─ CLIPS ─ */}
          {activePanel === "clips" && (
            <div className="space-y-3">
              <p className="text-[10px] font-semibold text-gray-400 uppercase tracking-wider">Clip Settings</p>

              {/* Selected clip info */}
              <div className="bg-gray-800 rounded-xl p-3 space-y-1">
                <p className="text-xs font-semibold text-white truncate">{sel.title}</p>
                <p className="text-[9px] text-gray-500">Duration: {fmt(duration)}</p>
                {sel.localFile && <p className="text-[9px] text-blue-400">📁 Local file (not saved to cloud)</p>}
              </div>

              {/* Re-upload if local */}
              {sel.localFile && (
                <label className="w-full flex items-center justify-center gap-2 py-2 rounded-xl bg-blue-600/20 hover:bg-blue-600/30 border border-blue-500/30 text-blue-400 text-xs cursor-pointer transition">
                  <Upload size={12}/> Re-upload this clip
                  <input type="file" accept={ACCEPTED_VIDEO_TYPES} className="hidden" onChange={e => {
                    const file = e.target.files?.[0];
                    if (!file) return;
                    const url = URL.createObjectURL(file);
                    updateClip({ url, title: file.name.replace(/\.[^/.]+$/, ""), localFile: true });
                    e.target.value = "";
                  }}/>
                </label>
              )}

              {/* Duplicate / Delete */}
              <div className="flex gap-2">
                <button onClick={() => duplicateClip(sel.id)}
                  className="flex-1 flex items-center justify-center gap-1 py-1.5 bg-gray-700 hover:bg-gray-600 text-gray-300 text-[10px] rounded-lg transition">
                  <Copy size={11}/> Duplicate
                </button>
                {clips.length > 1 && (
                  <button onClick={() => deleteClip(sel.id)}
                    className="flex-1 flex items-center justify-center gap-1 py-1.5 bg-red-600/20 hover:bg-red-600/30 text-red-400 text-[10px] rounded-lg transition">
                    <Trash2 size={11}/> Delete
                  </button>
                )}
              </div>

              {/* Reorder */}
              <div className="flex gap-2">
                <button onClick={() => reorderClip(sel.id, "up")}
                  className="flex-1 py-1.5 bg-gray-700 hover:bg-gray-600 text-gray-300 text-[10px] rounded-lg transition">↑ Move Up</button>
                <button onClick={() => reorderClip(sel.id, "down")}
                  className="flex-1 py-1.5 bg-gray-700 hover:bg-gray-600 text-gray-300 text-[10px] rounded-lg transition">↓ Move Down</button>
              </div>

              <Slider label="Opacity" value={sel.opacity} min={0} max={100}
                onChange={v => updateClip({ opacity: v })}
                onReset={() => updateClip({ opacity: 100 })} unit="%"/>
            </div>
          )}

          {/* ─ FILTER ─ */}
          {activePanel === "filter" && (
            <div className="space-y-3">
              <p className="text-[10px] font-semibold text-gray-400 uppercase tracking-wider">Filter Presets</p>
              <div className="grid grid-cols-2 gap-1.5">
                {FILTER_PRESETS.map(f => (
                  <button key={f.name} onClick={() => updateClip({ brightness:f.brightness, contrast:f.contrast, saturation:f.saturation, hue:f.hue, sepia:f.sepia, grayscale:f.grayscale })}
                    className="flex flex-col items-center py-2 px-1 rounded-lg bg-gray-800 hover:bg-gray-700 transition border border-gray-700 hover:border-indigo-500">
                    <div className="w-full h-8 rounded mb-1 overflow-hidden">
                      <div className="w-full h-full bg-linear-to-br from-blue-500 to-purple-500"
                        style={{ filter:`brightness(${f.brightness}%) contrast(${f.contrast}%) saturate(${f.saturation}%) sepia(${f.sepia}%) grayscale(${f.grayscale}%)` }}/>
                    </div>
                    <span className="text-[8px] text-gray-300">{f.name}</span>
                  </button>
                ))}
              </div>
            </div>
          )}

          {/* ─ ADJUST ─ */}
          {activePanel === "adjust" && (
            <div className="space-y-2">
              <div className="flex items-center justify-between">
                <p className="text-[10px] font-semibold text-gray-400 uppercase tracking-wider">Adjustments</p>
                <button onClick={() => updateClip({ brightness:100,contrast:100,saturation:100,hue:0,blur:0,sepia:0,grayscale:0,vignette:0,temperature:0,sharpness:0 })}
                  className="flex items-center gap-1 text-[9px] text-gray-500 hover:text-gray-300 transition">
                  <RotateCcw size={9}/> Reset
                </button>
              </div>
              <Slider label="Brightness" value={sel.brightness} min={0}   max={200} onChange={v=>updateClip({brightness:v})}  onReset={()=>updateClip({brightness:100})} unit="%"/>
              <Slider label="Contrast"   value={sel.contrast}   min={0}   max={200} onChange={v=>updateClip({contrast:v})}    onReset={()=>updateClip({contrast:100})}   unit="%"/>
              <Slider label="Saturation" value={sel.saturation} min={0}   max={200} onChange={v=>updateClip({saturation:v})}  onReset={()=>updateClip({saturation:100})} unit="%"/>
              <Slider label="Hue"        value={sel.hue}        min={0}   max={360} onChange={v=>updateClip({hue:v})}         onReset={()=>updateClip({hue:0})}          unit="°"/>
              <Slider label="Blur"       value={sel.blur}       min={0}   max={20}  step={0.5} onChange={v=>updateClip({blur:v})} onReset={()=>updateClip({blur:0})}     unit="px"/>
              <Slider label="Sepia"      value={sel.sepia}      min={0}   max={100} onChange={v=>updateClip({sepia:v})}       onReset={()=>updateClip({sepia:0})}        unit="%"/>
              <Slider label="Grayscale"  value={sel.grayscale}  min={0}   max={100} onChange={v=>updateClip({grayscale:v})}  onReset={()=>updateClip({grayscale:0})}    unit="%"/>
              <Slider label="Vignette"   value={sel.vignette}   min={0}   max={30}  onChange={v=>updateClip({vignette:v})}   onReset={()=>updateClip({vignette:0})}     unit=""/>
            </div>
          )}

          {/* ─ TRANSFORM ─ */}
          {activePanel === "transform" && (
            <div className="space-y-3">
              <p className="text-[10px] font-semibold text-gray-400 uppercase tracking-wider">Transform</p>

              {/* Flip */}
              <div>
                <p className="text-[9px] text-gray-500 mb-1.5">Flip</p>
                <div className="flex gap-2">
                  <button onClick={() => updateClip({ flipH: !sel.flipH })}
                    className={`flex-1 flex items-center justify-center gap-1 py-2 rounded-lg text-[10px] font-medium transition ${sel.flipH ? "bg-indigo-600 text-white" : "bg-gray-700 text-gray-400 hover:text-white"}`}>
                    <FlipHorizontal size={12}/> Horizontal
                  </button>
                  <button onClick={() => updateClip({ flipV: !sel.flipV })}
                    className={`flex-1 flex items-center justify-center gap-1 py-2 rounded-lg text-[10px] font-medium transition ${sel.flipV ? "bg-indigo-600 text-white" : "bg-gray-700 text-gray-400 hover:text-white"}`}>
                    <FlipVertical size={12}/> Vertical
                  </button>
                </div>
              </div>

              {/* Rotate */}
              <div>
                <p className="text-[9px] text-gray-500 mb-1.5">Rotation</p>
                <div className="grid grid-cols-4 gap-1.5 mb-2">
                  {[0, 90, 180, 270].map(deg => (
                    <button key={deg} onClick={() => updateClip({ rotate: deg })}
                      className={`py-2 rounded text-[9px] font-medium transition ${sel.rotate === deg ? "bg-indigo-600 text-white" : "bg-gray-800 text-gray-400 hover:bg-gray-700 hover:text-white"}`}>
                      {deg}°
                    </button>
                  ))}
                </div>
                <Slider label="Custom" value={sel.rotate} min={-180} max={180}
                  onChange={v => updateClip({ rotate: v })}
                  onReset={() => updateClip({ rotate: 0 })} unit="°"/>
              </div>

              {/* Aspect ratio resize helper */}
              <div>
                <p className="text-[9px] text-gray-500 mb-1.5">Aspect Ratio Info</p>
                <div className="grid grid-cols-2 gap-1.5">
                  {["16:9 (Landscape)","9:16 (Portrait)","1:1 (Square)","4:3 (Classic)"].map(r => (
                    <div key={r} className="py-1.5 px-2 bg-gray-800 rounded text-[9px] text-gray-400 text-center">{r}</div>
                  ))}
                </div>
                <p className="text-[9px] text-gray-600 mt-1">Video aspect is controlled by the source file. Use rotate/flip to adjust display.</p>
              </div>
            </div>
          )}

          {/* ─ TEXT ─ */}
          {activePanel === "text" && (
            <div className="space-y-3">
              <p className="text-[10px] font-semibold text-gray-400 uppercase tracking-wider">Text Overlays</p>

              {/* Add new */}
              <div className="space-y-2">
                <textarea value={overlayText} onChange={e => setOverlayText(e.target.value)} rows={2}
                  placeholder="Overlay text…"
                  className="w-full bg-gray-800 border border-gray-700 text-white text-xs rounded-lg px-2 py-1.5 resize-none focus:outline-none focus:border-indigo-500"/>

                <div className="grid grid-cols-2 gap-1.5">
                  <select value={overlayFont} onChange={e => setOverlayFont(e.target.value)}
                    className="h-6 text-[9px] bg-gray-800 border border-gray-700 text-white rounded px-1 focus:outline-none">
                    {FONTS.map(f => <option key={f} value={f}>{f}</option>)}
                  </select>
                  <input type="number" value={overlayFontSize} onChange={e => setOverlayFontSize(Number(e.target.value))}
                    className="h-6 text-[9px] bg-gray-800 border border-gray-700 text-white rounded px-1 focus:outline-none"
                    placeholder="Size" min={8} max={120}/>
                </div>

                <div className="flex items-center gap-2">
                  <span className="text-[9px] text-gray-500 w-10">Color</span>
                  <input type="color" value={overlayColor} onChange={e => setOverlayColor(e.target.value)}
                    className="w-7 h-7 rounded border border-gray-700 cursor-pointer bg-transparent"/>
                  <span className="text-[9px] text-gray-500 w-6">BG</span>
                  <input type="color" value={overlayBg === "transparent" ? "#000000" : overlayBg}
                    onChange={e => setOverlayBg(e.target.value)}
                    className="w-7 h-7 rounded border border-gray-700 cursor-pointer bg-transparent"/>
                  <button onClick={() => setOverlayBg("transparent")}
                    className="text-[8px] text-red-400 hover:text-red-300">None</button>
                </div>

                <div className="flex gap-1">
                  <button onClick={() => setOverlayBold(!overlayBold)}
                    className={`w-7 h-7 flex items-center justify-center rounded text-xs font-bold transition ${overlayBold ? "bg-indigo-600 text-white" : "bg-gray-700 text-gray-400"}`}>B</button>
                  <button onClick={() => setOverlayItalic(!overlayItalic)}
                    className={`w-7 h-7 flex items-center justify-center rounded text-xs italic transition ${overlayItalic ? "bg-indigo-600 text-white" : "bg-gray-700 text-gray-400"}`}>I</button>
                </div>

                {/* Position */}
                <div className="space-y-1">
                  <p className="text-[9px] text-gray-500">Position</p>
                  <div className="flex items-center gap-1">
                    <span className="text-[9px] text-gray-600 w-3">X</span>
                    <input type="range" min={5} max={95} value={overlayX} onChange={e => setOverlayX(Number(e.target.value))} className="flex-1 h-1 accent-indigo-500"/>
                    <span className="text-[9px] text-gray-500 w-6">{overlayX}%</span>
                  </div>
                  <div className="flex items-center gap-1">
                    <span className="text-[9px] text-gray-600 w-3">Y</span>
                    <input type="range" min={5} max={95} value={overlayY} onChange={e => setOverlayY(Number(e.target.value))} className="flex-1 h-1 accent-indigo-500"/>
                    <span className="text-[9px] text-gray-500 w-6">{overlayY}%</span>
                  </div>
                </div>

                <p className="text-[9px] text-gray-600">Appears: {fmt(currentTime)} → {fmt(currentTime + 5)}</p>
                <button onClick={addTextOverlay}
                  className="w-full py-1.5 bg-indigo-600 hover:bg-indigo-500 text-white text-xs rounded-lg transition font-medium">
                  + Add at {fmt(currentTime)}
                </button>
              </div>

              {/* Existing overlays */}
              {sel.textOverlays.length > 0 && (
                <div>
                  <p className="text-[9px] text-gray-500 mb-1.5">Added ({sel.textOverlays.length})</p>
                  <div className="space-y-1">
                    {sel.textOverlays.map(o => (
                      <div key={o.id}
                        className={`bg-gray-800 rounded-lg px-2 py-1.5 group cursor-pointer border-2 transition ${editingOverlayId === o.id ? "border-indigo-500" : "border-transparent hover:border-gray-600"}`}
                        onClick={() => setEditingOverlayId(editingOverlayId === o.id ? null : o.id)}>
                        <div className="flex items-center justify-between">
                          <p className="text-[9px] text-white truncate flex-1">{o.text}</p>
                          <div className="flex gap-1 shrink-0 ml-1">
                            <button onClick={e => { e.stopPropagation(); if(videoRef.current)videoRef.current.currentTime=o.startTime; }}
                              className="text-[8px] text-gray-500 hover:text-white p-0.5"><Play size={8}/></button>
                            <button onClick={e => { e.stopPropagation(); removeOverlay(o.id); }}
                              className="text-[8px] text-red-500 p-0.5"><Trash2 size={8}/></button>
                          </div>
                        </div>
                        <p className="text-[8px] text-gray-600">{fmt(o.startTime)} → {fmt(o.endTime)}</p>

                        {/* Inline edit */}
                        {editingOverlayId === o.id && (
                          <div className="mt-2 space-y-1 pt-2 border-t border-gray-700">
                            <input value={o.text} onChange={e => updateOverlay(o.id, { text: e.target.value })}
                              className="w-full bg-gray-700 text-white text-[9px] rounded px-2 py-1 focus:outline-none"/>
                            <div className="flex gap-1">
                              <input type="number" value={o.startTime} step={0.5} onChange={e => updateOverlay(o.id, { startTime: Number(e.target.value) })}
                                className="flex-1 bg-gray-700 text-white text-[9px] rounded px-1 py-0.5 focus:outline-none" placeholder="Start"/>
                              <input type="number" value={o.endTime} step={0.5} onChange={e => updateOverlay(o.id, { endTime: Number(e.target.value) })}
                                className="flex-1 bg-gray-700 text-white text-[9px] rounded px-1 py-0.5 focus:outline-none" placeholder="End"/>
                            </div>
                            <div className="flex gap-1">
                              <input type="color" value={o.color} onChange={e => updateOverlay(o.id, { color: e.target.value })}
                                className="w-6 h-5 rounded cursor-pointer border-0"/>
                              <input type="number" value={o.fontSize} onChange={e => updateOverlay(o.id, { fontSize: Number(e.target.value) })}
                                className="flex-1 bg-gray-700 text-white text-[9px] rounded px-1 py-0.5 focus:outline-none" placeholder="Size"/>
                            </div>
                          </div>
                        )}
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>
          )}

          {/* ─ AUDIO ─ */}
          {activePanel === "audio" && (
            <div className="space-y-3">
              <p className="text-[10px] font-semibold text-gray-400 uppercase tracking-wider">Audio</p>
              <Slider label="Volume" value={Math.round(sel.volume * 100)} min={0} max={150}
                onChange={v => updateClip({ volume: v / 100 })}
                onReset={() => updateClip({ volume: 1 })} unit="%"/>
              <div className="grid grid-cols-3 gap-1 mt-1">
                {[{label:"Mute",v:0},{label:"50%",v:50},{label:"100%",v:100},{label:"125%",v:125},{label:"150%",v:150}].map(p => (
                  <button key={p.label} onClick={() => updateClip({ volume: p.v / 100 })}
                    className={`py-1.5 text-[9px] rounded-lg transition font-medium ${Math.round(sel.volume*100)===p.v ? "bg-indigo-600 text-white" : "bg-gray-700 text-gray-400 hover:text-white"}`}>
                    {p.label}
                  </button>
                ))}
              </div>
              <div className="bg-gray-800 rounded-lg p-2.5 text-[9px] text-gray-400 space-y-1">
                <p className="font-semibold text-gray-300 mb-1">Note</p>
                <p>🔇 Mute: Remove all audio from clip</p>
                <p>📢 &gt;100%: Boost audio beyond original</p>
                <p className="text-gray-600 mt-1">Full audio mixing requires server-side processing tools like FFmpeg.</p>
              </div>
            </div>
          )}

          {/* ─ SPEED ─ */}
          {activePanel === "speed" && (
            <div className="space-y-3">
              <p className="text-[10px] font-semibold text-gray-400 uppercase tracking-wider">Playback Speed</p>
              <div className="grid grid-cols-2 gap-1.5">
                {PLAYBACK_RATES.map(r => (
                  <button key={r} onClick={() => updateClip({ playbackRate: r })}
                    className={`py-2.5 rounded-lg text-xs font-semibold transition ${sel.playbackRate === r ? "bg-indigo-600 text-white" : "bg-gray-800 text-gray-400 hover:bg-gray-700 hover:text-white"}`}>
                    {r}x
                    {r === 1 && <span className="text-[8px] block opacity-60">Normal</span>}
                    {r < 1  && <span className="text-[8px] block opacity-60">Slow</span>}
                    {r > 1  && <span className="text-[8px] block opacity-60">Fast</span>}
                  </button>
                ))}
              </div>
              <div className="bg-gray-800 rounded-xl p-3 text-[9px] text-gray-400 space-y-1">
                <p>🐢 0.25x — 0.5x: Slow motion</p>
                <p>⚡ 1x: Normal speed</p>
                <p>🚀 1.5x — 2x: Fast forward</p>
                <p>💨 3x — 4x: Time-lapse</p>
              </div>
            </div>
          )}

          {/* ─ TRIM / CROP ─ */}
          {activePanel === "crop" && (
            <div className="space-y-3">
              <p className="text-[10px] font-semibold text-gray-400 uppercase tracking-wider">Trim & Cut</p>

              {/* Trim sliders */}
              <div>
                <p className="text-[9px] text-gray-500 mb-2">Set In / Out Points</p>
                <Slider label="Start (In)"
                  value={Number(sel.startTrim.toFixed(1))}
                  min={0} max={Math.max(duration - 0.1, 0)} step={0.1}
                  onChange={v => { updateClip({ startTrim: v }); if(videoRef.current)videoRef.current.currentTime=v; }}
                  onReset={() => updateClip({ startTrim: 0 })} unit="s"/>
                <div className="mt-2"/>
                <Slider label="End (Out)"
                  value={Number((sel.endTrim || duration).toFixed(1))}
                  min={sel.startTrim + 0.1} max={duration} step={0.1}
                  onChange={v => updateClip({ endTrim: v })}
                  onReset={() => updateClip({ endTrim: null })} unit="s"/>
              </div>

              {/* Quick trim buttons */}
              <div className="space-y-1.5">
                <button onClick={() => updateClip({ startTrim: currentTime })}
                  className="w-full flex items-center justify-center gap-1.5 py-2 bg-indigo-600/20 hover:bg-indigo-600/30 border border-indigo-500/30 text-indigo-300 text-[10px] rounded-lg transition font-medium">
                  <Scissors size={11}/> Set In Point at {fmt(currentTime)}
                </button>
                <button onClick={() => updateClip({ endTrim: currentTime })}
                  className="w-full flex items-center justify-center gap-1.5 py-2 bg-orange-600/20 hover:bg-orange-600/30 border border-orange-500/30 text-orange-300 text-[10px] rounded-lg transition font-medium">
                  <Scissors size={11}/> Set Out Point at {fmt(currentTime)}
                </button>
                <button onClick={() => updateClip({ startTrim: 0, endTrim: null })}
                  className="w-full flex items-center justify-center gap-1 py-1.5 bg-gray-700 hover:bg-gray-600 text-gray-300 text-[9px] rounded-lg transition">
                  <RotateCcw size={9}/> Reset Trim
                </button>
              </div>

              {/* Trim summary */}
              {(sel.startTrim > 0 || sel.endTrim) && (
                <div className="bg-gray-800 rounded-lg p-2.5 text-[9px] space-y-1">
                  <p className="text-gray-400">Active trim:</p>
                  <p className="text-white font-mono">{fmt(sel.startTrim)} → {fmt(sel.endTrim || duration)}</p>
                  <p className="text-gray-500">Duration: {fmt((sel.endTrim || duration) - sel.startTrim)}</p>
                </div>
              )}

              <div className="bg-gray-800 rounded-xl p-3 text-[9px] text-gray-500 space-y-1">
                <p className="font-semibold text-gray-400">Tip</p>
                <p>Seek to a point in the video, then click &quot;Set In/Out Point&quot; to trim to that position.</p>
              </div>
            </div>
          )}
        </div>
      </div>

      {/* ══ ADD CLIP MODAL ══ */}
      {showAddModal && (
        <div className="fixed inset-0 z-50 bg-black/70 backdrop-blur-sm flex items-center justify-center p-4"
          onClick={() => setShowAddModal(false)}
          onDrop={handleDrop}
          onDragOver={handleDragOver}
          onDragLeave={handleDragLeave}>
          <div className="bg-gray-900 rounded-2xl p-5 w-96 border border-gray-700 shadow-2xl"
            onClick={e => e.stopPropagation()}>

            <div className="flex items-center justify-between mb-4">
              <h2 className="text-sm font-bold">Add Video Clip</h2>
              <button onClick={() => setShowAddModal(false)} className="text-gray-500 hover:text-white transition">
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
              </button>
            </div>

            {/* Tabs */}
            <div className="flex gap-1 mb-4 bg-gray-800 rounded-xl p-1">
              {(["upload","url"] as const).map(tab => (
                <button key={tab} onClick={() => setAddTab(tab)}
                  className={`flex-1 py-1.5 rounded-lg text-xs font-semibold capitalize transition ${addTab===tab?"bg-indigo-600 text-white":"text-gray-400 hover:text-white"}`}>
                  {tab === "upload" ? "📁 From Desktop" : "🔗 From URL"}
                </button>
              ))}
            </div>

            {/* Upload Tab */}
            {addTab === "upload" && (
              <div className="space-y-3">
                <div
                  ref={uploadDropRef}
                  onDrop={e => { e.preventDefault(); setIsDraggingFile(false); const f=e.dataTransfer.files[0]; if(f)addFromFile(f); }}
                  onDragOver={e => { e.preventDefault(); setIsDraggingFile(true); }}
                  onDragLeave={() => setIsDraggingFile(false)}
                  className={`flex flex-col items-center justify-center gap-3 py-10 rounded-2xl border-2 border-dashed transition cursor-pointer ${isDraggingFile ? "border-indigo-400 bg-indigo-500/10" : "border-gray-600 hover:border-gray-500"}`}
                  onClick={() => fileInputRef.current?.click()}>
                  <Upload size={28} className={isDraggingFile ? "text-indigo-400" : "text-gray-500"}/>
                  <div className="text-center">
                    <p className="text-sm font-semibold text-gray-300">
                      {isDraggingFile ? "Drop to add!" : "Drop video here"}
                    </p>
                    <p className="text-[11px] text-gray-500 mt-1">or click to browse from your computer</p>
                    <p className="text-[10px] text-gray-600 mt-1">MP4, WebM, MOV, AVI, MKV supported</p>
                  </div>
                  <label className="px-4 py-2 bg-indigo-600 hover:bg-indigo-500 text-white text-xs font-semibold rounded-lg cursor-pointer transition">
                    Browse Files
                    <input type="file" accept={ACCEPTED_VIDEO_TYPES} className="hidden" onChange={handleFileInput}/>
                  </label>
                </div>
                <p className="text-[9px] text-gray-600 text-center">
                  📝 Note: Local files are not saved to the cloud. Re-upload after refreshing.
                </p>
              </div>
            )}

            {/* URL Tab */}
            {addTab === "url" && (
              <div className="space-y-3">
                <div>
                  <label className="text-[10px] text-gray-400 mb-1 block font-semibold">Title</label>
                  <input value={newTitle} onChange={e => setNewTitle(e.target.value)} placeholder="My video"
                    className="w-full bg-gray-800 border border-gray-600 rounded-lg px-3 py-2 text-xs outline-none focus:border-indigo-500 text-white"/>
                </div>
                <div>
                  <label className="text-[10px] text-gray-400 mb-1 block font-semibold">Video URL</label>
                  <input value={newUrl} onChange={e => { setNewUrl(e.target.value); setUrlError(""); }}
                    onKeyDown={e => e.key === "Enter" && addFromUrl()}
                    placeholder="https://example.com/video.mp4" autoFocus
                    className="w-full bg-gray-800 border border-gray-600 rounded-lg px-3 py-2 text-xs outline-none focus:border-indigo-500 text-white font-mono"/>
                  {urlError && <p className="text-red-400 text-[10px] mt-1">{urlError}</p>}
                  <p className="text-[9px] text-gray-600 mt-1">Direct link to .mp4, .webm, or .ogg file</p>
                </div>
                <div className="flex gap-2 mt-2">
                  <button onClick={addFromUrl} className="flex-1 bg-indigo-600 hover:bg-indigo-500 text-white py-2 rounded-lg text-xs font-semibold transition">Add Video</button>
                  <button onClick={() => setShowAddModal(false)} className="flex-1 bg-gray-700 hover:bg-gray-600 text-white py-2 rounded-lg text-xs transition">Cancel</button>
                </div>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import { useEffect, useMemo, useState } from "react";
import { Card, CardHeader } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { ScrollArea, ScrollBar } from "@/components/ui/scroll-area";
import { Separator } from "@/components/ui/separator";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { ChevronLeft, ChevronRight, ChevronDown, Plus } from "lucide-react";
import TimelineItemModal from "@/components/TimelineItemmodal";
import { useTheme } from "next-themes";

type TimelineItem = {
  _id: string;
  title: string;
  startDate: string;
  endDate: string;
  assignedTo?: string;
  status?: string;
  comment?: string;
};

function startOfMonth(d: Date) {
  return new Date(d.getFullYear(), d.getMonth(), 1);
}

function endOfMonth(d: Date) {
  return new Date(d.getFullYear(), d.getMonth() + 1, 0);
}

function addDays(d: Date, days: number) {
  const x = new Date(d);
  x.setDate(x.getDate() + days);
  return x;
}

function daysBetween(a: Date, b: Date) {
  return Math.round((b.getTime() - a.getTime()) / (1000 * 60 * 60 * 24));
}

function formatMonthYear(d: Date) {
  return d.toLocaleString("en-US", { month: "long", year: "numeric" });
}

export default function TimelineView({ databaseId }: { databaseId: string }) {
  const [items, setItems] = useState<TimelineItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedItem, setSelectedItem] = useState<TimelineItem | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const { resolvedTheme } = useTheme();
  const isDark = resolvedTheme === "dark";

  // 🔥 fixed route name: database-items
  const fetchItems = async () => {
    try {
      setLoading(true);
      const res = await fetch(
        `/api/database_items?databaseId=${databaseId}`
      );
      const data = await res.json();
      setItems(data);
    } catch (e) {
      console.log("Timeline fetch error:", e);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchItems();
  }, [databaseId]);

  const handleItemClick = (item: TimelineItem) => {
    setSelectedItem(item);
    setIsModalOpen(true);
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setSelectedItem(null);
  };

  const handleSaved = () => {
    fetchItems();
  };

  // ---- Determine timeline month (like Notion screenshot)
  const monthDate = useMemo(() => {
    if (items.length === 0) return new Date();
    return new Date(items[0].startDate);
  }, [items]);

  const monthStart = useMemo(() => startOfMonth(monthDate), [monthDate]);
  const monthEnd = useMemo(() => endOfMonth(monthDate), [monthDate]);

  // ---- Visible days range
  // Notion shows partial previous days too, so we show -3 days before monthStart
  const rangeStart = useMemo(() => addDays(monthStart, -3), [monthStart]);
  const rangeEnd = useMemo(() => addDays(monthEnd, 2), [monthEnd]);

  const totalDays = Math.max(1, daysBetween(rangeStart, rangeEnd) + 1);

  // Today position
  const today = new Date();
  const todayOffset = daysBetween(rangeStart, today);
  const todayPercent = (todayOffset / totalDays) * 100;

  // Layout
  const ROW_HEIGHT = 56;
  const DAY_COL_WIDTH = 70; // Notion-ish
  const GRID_WIDTH = totalDays * DAY_COL_WIDTH;

  if (loading) {
    return (
      <Card className="p-6">
        <p className="text-sm text-muted-foreground">Loading timeline...</p>
      </Card>
    );
  }

  return (
    <Card className="overflow-hidden">
      {/* ======= HEADER (like Notion) ======= */}
      <CardHeader className="flex flex-row items-center justify-between">
        <div className="flex items-center gap-3">
          <Button variant="ghost" size="icon" className="h-8 w-8">
            <ChevronRight className="h-4 w-4" />
          </Button>
          <h2 className="font-semibold text-base">{formatMonthYear(monthStart)}</h2>
        </div>

        <div className="flex items-center gap-4 text-sm">
          <Button variant="outline" size="sm">
            Manage in Calendar
          </Button>

          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <Button variant="ghost" size="sm" className="gap-1">
                Month
                <ChevronDown className="h-3 w-3" />
              </Button>
            </DropdownMenuTrigger>
            <DropdownMenuContent align="end">
              <DropdownMenuItem>Day</DropdownMenuItem>
              <DropdownMenuItem>Week</DropdownMenuItem>
              <DropdownMenuItem>Month</DropdownMenuItem>
              <DropdownMenuItem>Year</DropdownMenuItem>
            </DropdownMenuContent>
          </DropdownMenu>

          <div className="flex items-center gap-2">
            <Button variant="ghost" size="icon" className="h-8 w-8">
              <ChevronLeft className="h-4 w-4" />
            </Button>
            <Button variant="ghost" size="sm">
              Today
            </Button>
            <Button variant="ghost" size="icon" className="h-8 w-8">
              <ChevronRight className="h-4 w-4" />
            </Button>
          </div>
        </div>
      </CardHeader>

      <Separator />

      {/* ======= GRID ======= */}
      <ScrollArea className="w-full">
        <div style={{ minWidth: GRID_WIDTH + 260 }}>
          {/* Top Day Row */}
          <div className="flex border-b">
            {/* left empty column like Notion */}
            <div className="w-[260px] shrink-0 bg-background" />

            <div
              className="relative"
              style={{ width: GRID_WIDTH, height: 44 }}
            >
              {/* alternating day columns background */}
              <div className="absolute inset-0 flex">
                {Array.from({ length: totalDays }).map((_, i) => (
                  <div
                    key={i}
                    className={i % 2 === 0 ? "bg-background" : "bg-muted/30"}
                    style={{ width: DAY_COL_WIDTH }}
                  />
                ))}
              </div>

              {/* day numbers */}
              <div className="absolute inset-0 flex">
                {Array.from({ length: totalDays }).map((_, i) => {
                  const d = addDays(rangeStart, i);
                  const dayNum = d.getDate();

                  const isToday =
                    d.toDateString() === new Date().toDateString();

                  return (
                    <div
                      key={i}
                      className="flex items-center justify-center text-sm text-muted-foreground"
                      style={{ width: DAY_COL_WIDTH }}
                    >
                      <div
                        className={`w-9 h-9 flex items-center justify-center rounded-full transition-colors ${
                          isToday
                            ? "bg-red-500 text-white font-bold"
                            : "hover:bg-muted"
                        }`}
                      >
                        {dayNum}
                      </div>
                    </div>
                  );
                })}
              </div>

              {/* today red dot */}
              {todayOffset >= 0 && todayOffset <= totalDays && (
                <div
                  className="absolute top-[38px] w-3 h-3 rounded-full bg-red-500"
                  style={{
                    left: `calc(${todayPercent}% - 6px)`,
                  }}
                />
              )}
            </div>
          </div>

          {/* Body rows */}
          <div className="relative flex">
            {/* left side column */}
            <div className="w-[260px] shrink-0 border-r bg-background">
              {/* empty spacing for items */}
              <div style={{ height: items.length * ROW_HEIGHT }} />

              {/* + New */}
              <Button variant="ghost" className="w-full justify-start gap-2 px-4 py-4">
                <Plus className="h-5 w-5" />
                <span>New</span>
              </Button>
            </div>

            {/* timeline canvas */}
            <div
              className="relative"
              style={{
                width: GRID_WIDTH,
                height: items.length * ROW_HEIGHT + 64,
              }}
            >
              {/* background columns */}
              <div className="absolute inset-0 flex">
                {Array.from({ length: totalDays }).map((_, i) => (
                  <div
                    key={i}
                    className={i % 2 === 0 ? "bg-background" : "bg-muted/30"}
                    style={{ width: DAY_COL_WIDTH }}
                  />
                ))}
              </div>

              {/* today red vertical line */}
              {todayOffset >= 0 && todayOffset <= totalDays && (
                <div
                  className="absolute top-0 bottom-0 w-0.5 bg-red-500/70"
                  style={{
                    left: `calc(${todayPercent}% - 1px)`,
                  }}
                />
              )}

              {/* items */}
              <div className="relative">
                {items.map((it, rowIndex) => {
                  const s = new Date(it.startDate);
                  const e = new Date(it.endDate);

                  const startOffset = daysBetween(rangeStart, s);
                  const duration = Math.max(1, daysBetween(s, e) + 1);

                  const leftPx = startOffset * DAY_COL_WIDTH;
                  const widthPx = Math.max(duration * DAY_COL_WIDTH, 180);

                  return (
                    <div
                      key={it._id}
                      className="relative"
                      style={{
                        height: ROW_HEIGHT,
                      }}
                    >
                      <Button
                        variant="outline"
                        className="absolute top-2.5 h-11 justify-between font-semibold"
                        style={{
                          left: leftPx,
                          width: widthPx,
                        }}
                        onClick={() => handleItemClick(it)}
                      >
                        <span>{it.title}</span>

                        {/* small handle circle (like Notion) */}
                        <div className="w-2 h-2 rounded-full bg-muted-foreground/30" />
                      </Button>
                    </div>
                  );
                })}
              </div>

              {/* bottom scrollbar fake bar look */}
              <div className="absolute bottom-4 left-1/2 -translate-x-1/2 w-[120px] h-2 rounded-full bg-muted-foreground/20" />
            </div>
          </div>
        </div>
        <ScrollBar orientation="horizontal" />
      </ScrollArea>

      {/* Timeline Item Modal */}
      {selectedItem && (
        <TimelineItemModal
          isOpen={isModalOpen}
          onClose={handleCloseModal}
          item={selectedItem}
          isDark={isDark}
          onSaved={handleSaved}
        />
      )}
    </Card>
  );
}

'use client';

import { useState, useEffect, useRef, useCallback } from 'react';

type Tool = "pen" | "select" | "eraser" | "rectangle" | "circle" | "triangle" | "line" | "arrow" | "text" | "sticky" | "highlighter" | "spray";

interface CanvasSnapshot { json: any; timestamp: number; }

export function Whiteboard({
  roomId, initialData, onChange, databaseId,
}: {
  roomId?: string; initialData?: any; onChange?: (data: any) => void; databaseId?: string;
}) {
  const canvasRef       = useRef<HTMLCanvasElement>(null);
  const fabricRef       = useRef<any>(null);
  const fabricLibRef    = useRef<any>(null);
  const drawingShapeRef = useRef<any>(null);
  const startPointRef   = useRef<{ x: number; y: number } | null>(null);
  const isDrawingRef    = useRef(false);
  const suppressUndoRef = useRef(false); // ✅ prevents dup on shape draw
  const saveTimerRef    = useRef<ReturnType<typeof setTimeout> | null>(null);

  const [isReady, setIsReady]             = useState(false);
  const [error, setError]                 = useState<string | null>(null);
  const [activeTool, setActiveTool]       = useState<Tool>("pen");
  const [activeColor, setActiveColor]     = useState("#1e1e1e");
  const [fillColor, setFillColor]         = useState("transparent");
  const [boardColor, setBoardColor]       = useState("#ffffff");
  const [brushSize, setBrushSize]         = useState(3);
  const [fontSize, setFontSize]           = useState(18);
  const [fontFamily, setFontFamily]       = useState("sans-serif");
  const [opacity, setOpacity]             = useState(100);
  const [isBold, setIsBold]               = useState(false);
  const [isItalic, setIsItalic]           = useState(false);
  const [isUnderline, setIsUnderline]     = useState(false);
  const [undoStack, setUndoStack]         = useState<CanvasSnapshot[]>([]);
  const [redoStack, setRedoStack]         = useState<CanvasSnapshot[]>([]);
  const [savedAt, setSavedAt]             = useState<string | null>(null);
  const [saving, setSaving]               = useState(false);
  const [zoom, setZoom]                   = useState(100);
  const [showColorPicker, setShowColorPicker] = useState<"stroke" | "fill" | null>(null);
  const colorPickerRef = useRef<HTMLDivElement>(null);

  // ✅ Load / Save state
  const [loadedOnce, setLoadedOnce] = useState(false);

  const [roomIdState] = useState<string>(
    () => roomId ?? `whiteboard-${Math.random().toString(36).substr(2, 9)}`
  );

  const normalizeShapeSelectionStyle = useCallback((canvas: any) => {
    canvas.getObjects().forEach((obj: any) => {
      const isText = obj?.type === "i-text" || obj?.type === "textbox";
      if (!isText) {
        obj.set({ hasControls: false, hasBorders: false, transparentCorners: true });
      }
    });
  }, []);

  useEffect(() => {
    const h = (e: MouseEvent) => {
      if (colorPickerRef.current && !colorPickerRef.current.contains(e.target as Node)) setShowColorPicker(null);
    };
    document.addEventListener("mousedown", h);
    return () => document.removeEventListener("mousedown", h);
  }, []);

  // ✅ Apply board color
  useEffect(() => {
    const canvas = fabricRef.current;
    if (!canvas) return;
    canvas.setBackgroundColor(boardColor, () => canvas.renderAll());
  }, [boardColor]);

  // ✅ Save to DB
  const saveToDatabase = useCallback(async (json: any) => {
    if (!databaseId) { onChange?.(json); return; }
    setSaving(true);
    try {
      await fetch(`/api/databases/${databaseId}/whiteboard`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ canvas: json }),
      });
      setSavedAt(new Date().toLocaleTimeString());
      onChange?.(json);
    } catch (err) { console.error("Save failed:", err); }
    finally { setSaving(false); }
  }, [databaseId, onChange]);

  // ✅ Push undo
  const pushUndo = useCallback(() => {
    if (suppressUndoRef.current) return;
    const canvas = fabricRef.current;
    if (!canvas) return;
    const json = canvas.toJSON();
    setUndoStack(prev => [...prev.slice(-29), { json, timestamp: Date.now() }]);
    setRedoStack([]);
    if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
    saveTimerRef.current = setTimeout(() => saveToDatabase(json), 2000);
  }, [saveToDatabase]);

  // ✅ Init Fabric + Load from DB
  useEffect(() => {
    if (!canvasRef.current) return;
    let disposed = false;

    import("fabric").then((mod) => {
      if (disposed) return;
      const fabric = (mod.fabric ?? mod) as any;
      if (!fabric.EraserBrush && (mod as any).EraserBrush) {
        fabric.EraserBrush = (mod as any).EraserBrush;
      }
      fabricLibRef.current = fabric;

      const parent = canvasRef.current?.parentElement;
      const canvas = new fabric.Canvas(canvasRef.current, {
        isDrawingMode: true,
        backgroundColor: "#ffffff",
        width: parent?.offsetWidth || 900,
        height: parent?.offsetHeight || 560,
        preserveObjectStacking: true,
        renderOnAddRemove: false,
      });

      canvas.freeDrawingBrush.color = "#1e1e1e";
      canvas.freeDrawingBrush.width = 3;
      fabricRef.current = canvas;
      setIsReady(true);

      canvas.on("object:added",    () => { if (!suppressUndoRef.current) pushUndo(); });
      canvas.on("object:modified", () => { if (!suppressUndoRef.current) pushUndo(); });
      canvas.on("object:removed",  () => { if (!suppressUndoRef.current) pushUndo(); });

      const handleResize = () => {
        const p = canvasRef.current?.parentElement;
        if (!p) return;
        canvas.setWidth(p.offsetWidth);
        canvas.setHeight(p.offsetHeight);
        canvas.renderAll();
      };
      window.addEventListener("resize", handleResize);

      // ✅ Load saved canvas from DB or use initialData
      const loadCanvas = async () => {
        try {
          if (databaseId) {
            const res  = await fetch(`/api/databases/${databaseId}/whiteboard`);
            const data = await res.json();
            if (data.canvas) {
              suppressUndoRef.current = true;
              canvas.loadFromJSON(data.canvas, () => {
                normalizeShapeSelectionStyle(canvas);
                canvas.renderAll();
                suppressUndoRef.current = false;
              });
            } else if (initialData) {
              suppressUndoRef.current = true;
              canvas.loadFromJSON(initialData, () => {
                normalizeShapeSelectionStyle(canvas);
                canvas.renderAll();
                suppressUndoRef.current = false;
              });
            }
          } else if (initialData) {
            suppressUndoRef.current = true;
            canvas.loadFromJSON(initialData, () => {
              normalizeShapeSelectionStyle(canvas);
              canvas.renderAll();
              suppressUndoRef.current = false;
            });
          }
        } catch (e) { console.error("Load failed:", e); }
        finally { setLoadedOnce(true); }
      };

      setTimeout(loadCanvas, 300);

      return () => {
        window.removeEventListener("resize", handleResize);
        canvas.dispose();
      };
    }).catch(() => setError("Failed to load whiteboard"));

    return () => {
      disposed = true;
      if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
      fabricRef.current?.dispose();
    };
  }, [normalizeShapeSelectionStyle]);

  // ── Tool sync ──
  useEffect(() => {
    const canvas = fabricRef.current;
    const fabric = fabricLibRef.current;
    if (!canvas || !fabric) return;

    canvas.off("mouse:down");
    canvas.off("mouse:move");
    canvas.off("mouse:up");
    canvas.off("path:created");

    if (activeTool === "pen") {
      canvas.isDrawingMode = true; canvas.selection = true;
      const brush = new fabric.PencilBrush(canvas);
      brush.color = activeColor; brush.width = brushSize;
      canvas.freeDrawingBrush = brush;
    } else if (activeTool === "highlighter") {
      canvas.isDrawingMode = true; canvas.selection = true;
      const brush = new fabric.PencilBrush(canvas);
      brush.color = activeColor + "55"; brush.width = brushSize * 6;
      canvas.freeDrawingBrush = brush;
    } else if (activeTool === "spray") {
      canvas.isDrawingMode = true; canvas.selection = true;
      const brush = new (fabric.SprayBrush || fabric.PencilBrush)(canvas);
      brush.color = activeColor; brush.width = brushSize * 3;
      canvas.freeDrawingBrush = brush;
    } else if (activeTool === "eraser") {
      canvas.selection = false;

      const hasNativeEraser = typeof fabric.EraserBrush === "function";

      if (hasNativeEraser) {
        canvas.isDrawingMode = true;
        const brush = new fabric.EraserBrush(canvas);
        brush.width = Math.max(2, brushSize * 2.5);
        canvas.freeDrawingBrush = brush;

        let erasedSomething = false;

        const onMouseDown = () => {
          canvas.getObjects().forEach((obj: any) => {
            if (obj.erasable !== false) obj.set("erasable", true);
          });
          suppressUndoRef.current = true;
        };

        const onPathCreated = (opt: any) => {
          if (!opt?.path) return;
          erasedSomething = true;
          canvas.requestRenderAll();
        };

        const onMouseUp = () => {
          suppressUndoRef.current = false;
          if (erasedSomething) {
            pushUndo();
            erasedSomething = false;
          }
        };

        canvas.on("mouse:down", onMouseDown);
        canvas.on("path:created", onPathCreated);
        canvas.on("mouse:up", onMouseUp);

        return () => {
          canvas.off("mouse:down", onMouseDown);
          canvas.off("path:created", onPathCreated);
          canvas.off("mouse:up", onMouseUp);
          suppressUndoRef.current = false;
        };
      }

      // Fallback: delete intersected objects to avoid persistent mask artifacts.
      canvas.isDrawingMode = false;

      let erasedSomething = false;
      let isErasing = false;

      const eraseAtPointer = (opt: any) => {
        const pointer = canvas.getPointer(opt.e);
        const radius = Math.max(4, brushSize * 4);
        const topLeft = new fabric.Point(pointer.x - radius, pointer.y - radius);
        const bottomRight = new fabric.Point(pointer.x + radius, pointer.y + radius);
        const hitPoint = new fabric.Point(pointer.x, pointer.y);

        const toRemove = canvas.getObjects().filter((obj: any) => {
          if (!obj || obj.evented === false) return false;
          return obj.intersectsWithRect(topLeft, bottomRight, true) || obj.containsPoint(hitPoint);
        });

        if (toRemove.length > 0) {
          toRemove.forEach((obj: any) => canvas.remove(obj));
          erasedSomething = true;
          canvas.requestRenderAll();
        }
      };

      const onMouseDown = (opt: any) => {
        isErasing = true;
        suppressUndoRef.current = true;
        eraseAtPointer(opt);
      };

      const onMouseMove = (opt: any) => {
        if (!isErasing) return;
        eraseAtPointer(opt);
      };

      const onMouseUp = () => {
        isErasing = false;
        suppressUndoRef.current = false;
        if (erasedSomething) {
          pushUndo();
          erasedSomething = false;
        }
      };

      canvas.on("mouse:down", onMouseDown);
      canvas.on("mouse:move", onMouseMove);
      canvas.on("mouse:up", onMouseUp);

      return () => {
        canvas.off("mouse:down", onMouseDown);
        canvas.off("mouse:move", onMouseMove);
        canvas.off("mouse:up", onMouseUp);
        suppressUndoRef.current = false;
      };
    } else if (activeTool === "select") {
      canvas.isDrawingMode = false; canvas.selection = true;
    } else {
      canvas.isDrawingMode = false; canvas.selection = false; canvas.defaultCursor = "crosshair";

      const handleMouseDown = (opt: any) => {
        suppressUndoRef.current = true;
        const pointer = canvas.getPointer(opt.e);
        startPointRef.current = { x: pointer.x, y: pointer.y };
        isDrawingRef.current = true;
        const fill = fillColor === "transparent" ? "rgba(0,0,0,0)" : fillColor;
        let shape: any = null;

        if (activeTool === "rectangle") shape = new fabric.Rect({ left:pointer.x, top:pointer.y, width:0, height:0, fill, stroke:activeColor, strokeWidth:brushSize, opacity:opacity/100, selectable:false, evented:false });
        else if (activeTool === "circle") shape = new fabric.Ellipse({ left:pointer.x, top:pointer.y, rx:0, ry:0, fill, stroke:activeColor, strokeWidth:brushSize, opacity:opacity/100, selectable:false, evented:false });
        else if (activeTool === "triangle") shape = new fabric.Triangle({ left:pointer.x, top:pointer.y, width:0, height:0, fill, stroke:activeColor, strokeWidth:brushSize, opacity:opacity/100, selectable:false, evented:false });
        else if (activeTool === "line" || activeTool === "arrow") shape = new fabric.Line([pointer.x,pointer.y,pointer.x,pointer.y], { stroke:activeColor, strokeWidth:brushSize, opacity:opacity/100, selectable:false, evented:false });

        if (shape) { canvas.add(shape); canvas.renderAll(); drawingShapeRef.current = shape; }
      };

      const handleMouseMove = (opt: any) => {
        if (!isDrawingRef.current || !startPointRef.current || !drawingShapeRef.current) return;
        const pointer = canvas.getPointer(opt.e);
        const sp = startPointRef.current;
        const shape = drawingShapeRef.current;

        if (activeTool === "rectangle" || activeTool === "triangle") shape.set({ left:Math.min(pointer.x,sp.x), top:Math.min(pointer.y,sp.y), width:Math.abs(pointer.x-sp.x)||1, height:Math.abs(pointer.y-sp.y)||1 });
        else if (activeTool === "circle") shape.set({ left:Math.min(pointer.x,sp.x), top:Math.min(pointer.y,sp.y), rx:Math.abs(pointer.x-sp.x)/2||1, ry:Math.abs(pointer.y-sp.y)/2||1 });
        else if (activeTool === "line" || activeTool === "arrow") shape.set({ x2:pointer.x, y2:pointer.y });
        shape.setCoords();
        canvas.requestRenderAll();
      };

      const handleMouseUp = (opt: any) => {
        if (!isDrawingRef.current) return;
        isDrawingRef.current = false;
        const sp = startPointRef.current;
        const shape = drawingShapeRef.current;
        if (!shape) {
          startPointRef.current = null;
          suppressUndoRef.current = false;
          return;
        }

        const pointer = opt?.e ? canvas.getPointer(opt.e) : null;
        const drawDistance = sp && pointer
          ? Math.hypot(pointer.x - sp.x, pointer.y - sp.y)
          : 0;

        if (drawDistance < 2) {
          canvas.remove(shape);
        } else {
          shape.set({ selectable:true, evented:true, hasControls:false, hasBorders:false });
          shape.setCoords();
        }

        drawingShapeRef.current = null;
        startPointRef.current = null;
        canvas.discardActiveObject();
        canvas.requestRenderAll();
        suppressUndoRef.current = false;
        pushUndo();
      };

      canvas.on("mouse:down", handleMouseDown);
      canvas.on("mouse:move", handleMouseMove);
      canvas.on("mouse:up", handleMouseUp);

      return () => {
        canvas.off("mouse:down", handleMouseDown);
        canvas.off("mouse:move", handleMouseMove);
        canvas.off("mouse:up", handleMouseUp);
        canvas.selection = true; canvas.defaultCursor = "default";
      };
    }
  }, [activeTool, activeColor, fillColor, boardColor, brushSize, opacity, pushUndo]);

  const addText = async (sticky = false) => {
    const fabric = fabricLibRef.current;
    if (!fabric || !fabricRef.current) return;
    if (sticky) {
      const rect = new fabric.Rect({ left:80, top:80, width:160, height:120, fill:"#fef08a", stroke:"#ca8a04", strokeWidth:1, rx:4, ry:4 });
      const text = new fabric.IText("Sticky note", { left:160, top:140, fill:"#713f12", fontSize:14, fontFamily:"sans-serif", originX:"center", originY:"center" });
      fabricRef.current.add(new fabric.Group([rect,text],{left:80,top:80}));
    } else {
      const text = new fabric.IText("Type here...", { left:100, top:100, fill:activeColor, fontSize, fontFamily, fontWeight:isBold?"bold":"normal", fontStyle:isItalic?"italic":"normal", underline:isUnderline, opacity:opacity/100 });
      fabricRef.current.add(text);
      fabricRef.current.setActiveObject(text);
      text.enterEditing();
    }
    setActiveTool("select"); pushUndo();
  };

  const updateSelectedText = (props: Record<string,any>) => {
    const canvas = fabricRef.current;
    if (!canvas) return;
    const obj = canvas.getActiveObject();
    if (obj && (obj.type==="i-text"||obj.type==="textbox")) { obj.set(props); canvas.renderAll(); pushUndo(); }
  };

  const handleUndo = useCallback(() => {
    const canvas = fabricRef.current;
    if (!canvas || undoStack.length===0) return;
    const current = canvas.toJSON();
    const prev = undoStack[undoStack.length-1];
    setRedoStack(r=>[...r,{json:current,timestamp:Date.now()}]);
    setUndoStack(u=>u.slice(0,-1));
    suppressUndoRef.current = true;
    canvas.loadFromJSON(prev.json, ()=>{ canvas.renderAll(); suppressUndoRef.current=false; });
  }, [undoStack]);

  const handleRedo = useCallback(() => {
    const canvas = fabricRef.current;
    if (!canvas || redoStack.length===0) return;
    const current = canvas.toJSON();
    const next = redoStack[redoStack.length-1];
    setUndoStack(u=>[...u,{json:current,timestamp:Date.now()}]);
    setRedoStack(r=>r.slice(0,-1));
    suppressUndoRef.current = true;
    canvas.loadFromJSON(next.json, ()=>{ canvas.renderAll(); suppressUndoRef.current=false; });
  }, [redoStack]);

  const deleteSelected = () => {
    const canvas = fabricRef.current;
    if (!canvas) return;
    canvas.getActiveObjects().forEach((obj:any)=>canvas.remove(obj));
    canvas.discardActiveObject(); canvas.renderAll(); pushUndo();
  };

  const selectAll = () => {
    const canvas = fabricRef.current;
    if (!canvas) return;
    canvas.discardActiveObject();
    const sel = new (fabricLibRef.current.ActiveSelection)(canvas.getObjects(),{canvas});
    canvas.setActiveObject(sel); canvas.requestRenderAll(); setActiveTool("select");
  };

  const handleZoom = (delta: number) => {
    const canvas = fabricRef.current;
    if (!canvas) return;
    const z = Math.min(Math.max(zoom+delta,25),300);
    setZoom(z); canvas.setZoom(z/100); canvas.renderAll();
  };

  const handleClear = () => {
    if (!confirm("Clear the entire canvas?")) return;
    const canvas = fabricRef.current;
    if (!canvas) return;
    suppressUndoRef.current = true;
    canvas.clear();
    canvas.setBackgroundColor(boardColor, ()=>{ canvas.renderAll(); suppressUndoRef.current=false; pushUndo(); });
  };

  const handleExportPNG = () => {
    const canvas = fabricRef.current;
    if (!canvas) return;
    const url = canvas.toDataURL({format:"png",multiplier:2});
    const a = document.createElement("a"); a.href=url; a.download=`whiteboard-${Date.now()}.png`; a.click();
  };

  const handleExportSVG = () => {
    const canvas = fabricRef.current;
    if (!canvas) return;
    const svg = canvas.toSVG();
    const blob = new Blob([svg],{type:"image/svg+xml"});
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a"); a.href=url; a.download=`whiteboard-${Date.now()}.svg`; a.click();
    URL.revokeObjectURL(url);
  };

  const handleManualSave = () => {
    const canvas = fabricRef.current;
    if (!canvas) return;
    saveToDatabase(canvas.toJSON());
  };

  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      const tag = (e.target as HTMLElement).tagName;
      if (tag==="INPUT"||tag==="TEXTAREA") return;
      if ((e.ctrlKey||e.metaKey)&&e.key==="z") { e.preventDefault(); handleUndo(); }
      if ((e.ctrlKey||e.metaKey)&&e.key==="y") { e.preventDefault(); handleRedo(); }
      if ((e.ctrlKey||e.metaKey)&&e.key==="a") { e.preventDefault(); selectAll(); }
      if ((e.ctrlKey||e.metaKey)&&e.key==="s") { e.preventDefault(); handleManualSave(); }
      if ((e.key==="Delete"||e.key==="Backspace") && fabricRef.current?.getActiveObject()) { e.preventDefault(); deleteSelected(); }
      if (!e.ctrlKey&&!e.metaKey) {
        if (e.key==="v") setActiveTool("select");
        if (e.key==="p") setActiveTool("pen");
        if (e.key==="e") setActiveTool("eraser");
        if (e.key==="r") setActiveTool("rectangle");
        if (e.key==="c") setActiveTool("circle");
        if (e.key==="t") addText();
      }
    };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, [undoStack, redoStack, activeTool]);

  const COLORS = ["#000000","#ffffff","#ef4444","#f97316","#eab308","#22c55e","#3b82f6","#8b5cf6","#ec4899","#6b7280","#1e40af","#065f46","#7c2d12","#1e1b4b","#134e4a"];
  const FONTS  = ["sans-serif","serif","monospace","Georgia","Verdana","Arial","Trebuchet MS","Impact"];

  const ToolBtn = ({tool,icon,title,shortcut,onClick}:{tool?:Tool;icon:React.ReactNode;title:string;shortcut?:string;onClick?:()=>void}) => (
    <button onClick={onClick??( ()=>tool&&setActiveTool(tool))} title={`${title}${shortcut?` (${shortcut})`:""}`}
      className={`relative w-7 h-7 flex items-center justify-center rounded-md transition-all text-xs font-medium ${tool&&activeTool===tool?"bg-blue-600 text-white shadow-sm shadow-blue-400/40":"text-gray-500 hover:bg-gray-100 hover:text-gray-700"}`}>
      {icon}
    </button>
  );

  if (error) return (
    <div className="w-full h-full flex items-center justify-center bg-white">
      <div className="flex flex-col items-center gap-2">
        <span className="text-2xl">⚠️</span>
        <p className="text-xs text-red-500">{error}</p>
        <button onClick={()=>setError(null)} className="px-3 py-1 bg-red-500 text-white text-xs rounded-md">Dismiss</button>
      </div>
    </div>
  );

  return (
    <div className="flex flex-col w-full h-full overflow-hidden bg-white" style={{fontFamily:"system-ui, sans-serif"}}>

      {/* ROW 1 — File & Edit */}
      <div className="flex items-center gap-0.5 px-2 py-1 bg-gray-50 border-b border-gray-200 shrink-0 flex-wrap">
        <div className="flex items-center gap-0.5 pr-2 border-r border-gray-200">
          <ToolBtn title="Save" shortcut="Ctrl+S" onClick={handleManualSave}
            icon={saving ? <div className="w-3 h-3 border border-blue-500 border-t-transparent rounded-full animate-spin"/>
              : savedAt ? <span className="text-[9px] text-green-600">✓</span>
              : <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M19 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11l5 5v11a2 2 0 0 1-2 2z"/><polyline points="17 21 17 13 7 13 7 21"/><polyline points="7 3 7 8 15 8"/></svg>}
          />
          <ToolBtn title="Export PNG" onClick={handleExportPNG}
            icon={<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg>}
          />
          <ToolBtn title="Export SVG" onClick={handleExportSVG} icon={<span className="text-[8px] font-bold">SVG</span>}/>
        </div>
        <div className="flex items-center gap-0.5 px-2 border-r border-gray-200">
          <ToolBtn title="Undo" shortcut="Ctrl+Z" onClick={handleUndo}
            icon={<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><polyline points="9 14 4 9 9 4"/><path d="M20 20v-7a4 4 0 0 0-4-4H4"/></svg>}/>
          <ToolBtn title="Redo" shortcut="Ctrl+Y" onClick={handleRedo}
            icon={<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><polyline points="15 14 20 9 15 4"/><path d="M4 20v-7a4 4 0 0 1 4-4h12"/></svg>}/>
          <ToolBtn title="Select All" shortcut="Ctrl+A" onClick={selectAll}
            icon={<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><rect x="3" y="3" width="18" height="18" rx="2" strokeDasharray="4 2"/></svg>}/>
          <ToolBtn title="Delete selected" shortcut="Del" onClick={deleteSelected}
            icon={<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><polyline points="3 6 5 6 21 6"/><path d="M19 6l-1 14H6L5 6"/><path d="M10 11v6"/><path d="M14 11v6"/><path d="M9 6V4h6v2"/></svg>}/>
          <ToolBtn title="Clear canvas" onClick={handleClear}
            icon={<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M20 20H7L3 16l10-10 7 7-2.5 2.5"/><path d="M6 11l4 4"/></svg>}/>
        </div>
        <div className="flex items-center gap-1 px-2 border-r border-gray-200">
          <button onClick={()=>handleZoom(-10)} className="w-5 h-5 flex items-center justify-center rounded text-gray-500 hover:bg-gray-100 text-sm font-bold">−</button>
          <span className="text-[10px] text-gray-500 w-8 text-center">{zoom}%</span>
          <button onClick={()=>handleZoom(10)} className="w-5 h-5 flex items-center justify-center rounded text-gray-500 hover:bg-gray-100 text-sm font-bold">+</button>
          <button onClick={()=>{setZoom(100);fabricRef.current?.setZoom(1);fabricRef.current?.renderAll();}} className="text-[9px] text-gray-400 hover:text-gray-600 px-1">Reset</button>
        </div>
        <div className="ml-auto flex items-center gap-2">
          <span className={`w-1.5 h-1.5 rounded-full ${isReady?"bg-emerald-400":"bg-amber-400"}`}/>
          {saving && <span className="text-[9px] text-amber-500 animate-pulse">● Saving…</span>}
          {!saving && savedAt && <span className="text-[9px] text-emerald-500">✓ {savedAt}</span>}
        </div>
      </div>

      {/* ROW 2 — Tools */}
      <div className="flex items-center gap-0.5 px-2 py-1 bg-white border-b border-gray-200 shrink-0 flex-wrap">
        <div className="flex items-center gap-0.5 pr-2 border-r border-gray-200">
          <ToolBtn tool="select" title="Select" shortcut="V" icon={<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M5 3l14 9-7 1-4 7z"/></svg>}/>
          <ToolBtn tool="pen" title="Pen" shortcut="P" icon={<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M12 20h9"/><path d="M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4Z"/></svg>}/>
          <ToolBtn tool="highlighter" title="Highlighter" icon={<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="m9 11-6 6v3h3l6-6"/><path d="m22 12-4.6 4.6a2 2 0 0 1-2.8 0l-5.2-5.2a2 2 0 0 1 0-2.8L14 4"/></svg>}/>
          <ToolBtn tool="eraser" title="Eraser" shortcut="E" icon={<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M20 20H7L3 16l10-10 7 7-2.5 2.5"/><path d="M6 11l4 4"/></svg>}/>
        </div>
        <div className="flex items-center gap-0.5 px-2 border-r border-gray-200">
          <ToolBtn tool="rectangle" title="Rectangle" shortcut="R" icon={<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><rect x="3" y="5" width="18" height="14" rx="2"/></svg>}/>
          <ToolBtn tool="circle" title="Ellipse" shortcut="C" icon={<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><ellipse cx="12" cy="12" rx="10" ry="7"/></svg>}/>
          <ToolBtn tool="triangle" title="Triangle" icon={<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M12 3L2 21h20z"/></svg>}/>
          <ToolBtn tool="line" title="Line" icon={<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><line x1="3" y1="21" x2="21" y2="3"/></svg>}/>
          <ToolBtn tool="arrow" title="Arrow" icon={<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><line x1="3" y1="21" x2="21" y2="3"/><polyline points="11 3 21 3 21 13"/></svg>}/>
        </div>
        <div className="flex items-center gap-0.5 px-2 border-r border-gray-200">
          <ToolBtn tool="text" title="Text" shortcut="T" onClick={()=>addText(false)} icon={<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><polyline points="4 7 4 4 20 4 20 7"/><line x1="9" y1="20" x2="15" y2="20"/><line x1="12" y1="4" x2="12" y2="20"/></svg>}/>
          <ToolBtn tool="sticky" title="Sticky Note" onClick={()=>addText(true)} icon={<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M15.5 3H5a2 2 0 0 0-2 2v14c0 1.1.9 2 2 2h14a2 2 0 0 0 2-2V8.5L15.5 3Z"/><polyline points="15 3 15 9 21 9"/></svg>}/>
        </div>
        {/* Colors */}
        <div className="flex items-center gap-1.5 px-2 border-r border-gray-200 relative" ref={colorPickerRef}>
          <div className="flex flex-col items-center gap-0.5">
            <span className="text-[8px] text-gray-400">Stroke</span>
            <button onClick={()=>setShowColorPicker(showColorPicker==="stroke"?null:"stroke")}
              className="w-6 h-6 rounded border-2 border-gray-300 shadow-sm hover:border-gray-400 transition" style={{backgroundColor:activeColor}}/>
          </div>
          <div className="flex flex-col items-center gap-0.5">
            <span className="text-[8px] text-gray-400">Fill</span>
            <button onClick={()=>setShowColorPicker(showColorPicker==="fill"?null:"fill")}
              className="w-6 h-6 rounded border-2 border-gray-300 shadow-sm hover:border-gray-400 transition relative"
              style={{backgroundColor:fillColor==="transparent"?"white":fillColor}}>
              {fillColor==="transparent" && <div className="absolute inset-0 flex items-center justify-center"><div className="w-full h-[1px] bg-red-500 rotate-45"/></div>}
            </button>
          </div>
          {showColorPicker && (
            <div className="absolute top-full left-0 mt-1 z-50 bg-white border border-gray-200 rounded-xl shadow-xl p-3 w-52">
              <p className="text-[10px] font-semibold text-gray-500 mb-2 uppercase tracking-wider">{showColorPicker==="stroke"?"Stroke":"Fill"} Color</p>
              <div className="grid grid-cols-5 gap-1.5 mb-2">
                {COLORS.map(c=>(
                  <button key={c} onClick={()=>{if(showColorPicker==="stroke"){setActiveColor(c);if(activeTool==="eraser")setActiveTool("pen");}else setFillColor(c);setShowColorPicker(null);}}
                    className="w-7 h-7 rounded-lg border-2 transition hover:scale-110"
                    style={{backgroundColor:c,borderColor:(showColorPicker==="stroke"?activeColor:fillColor)===c?"#3b82f6":"#e5e7eb",boxShadow:c==="#ffffff"?"inset 0 0 0 1px #e5e7eb":undefined}}/>
                ))}
              </div>
              <div className="flex items-center gap-2">
                <input type="color" value={showColorPicker==="stroke"?activeColor:(fillColor==="transparent"?"#ffffff":fillColor)}
                  onChange={e=>showColorPicker==="stroke"?setActiveColor(e.target.value):setFillColor(e.target.value)}
                  className="w-7 h-7 rounded border border-gray-200 cursor-pointer"/>
                <span className="text-[10px] text-gray-400">Custom</span>
                {showColorPicker==="fill" && <button onClick={()=>{setFillColor("transparent");setShowColorPicker(null);}} className="ml-auto text-[9px] text-red-400 hover:text-red-600">None</button>}
              </div>
            </div>
          )}
        </div>
        <div className="flex items-center gap-1 px-2 border-r border-gray-200">
          <span className="text-[9px] text-gray-400">Size</span>
          <input type="range" min={1} max={30} value={brushSize} onChange={e=>setBrushSize(Number(e.target.value))} className="w-16 h-1 accent-blue-500 cursor-pointer"/>
          <span className="text-[9px] text-gray-500 w-4">{brushSize}</span>
        </div>
        <div className="flex items-center gap-1 px-2 border-r border-gray-200">
          <span className="text-[9px] text-gray-400">Opacity</span>
          <input type="range" min={10} max={100} value={opacity} onChange={e=>setOpacity(Number(e.target.value))} className="w-14 h-1 accent-blue-500 cursor-pointer"/>
          <span className="text-[9px] text-gray-500 w-6">{opacity}%</span>
        </div>
      </div>

      {/* ROW 3 — Text */}
      <div className="flex items-center gap-1 px-2 py-1 bg-gray-50 border-b border-gray-200 shrink-0 flex-wrap">
        <span className="text-[9px] text-gray-400 mr-1">Text:</span>
        <select value={fontFamily} onChange={e=>{setFontFamily(e.target.value);updateSelectedText({fontFamily:e.target.value});}}
          className="h-6 text-[10px] border border-gray-200 rounded px-1 bg-white text-gray-700 focus:outline-none focus:border-blue-400">
          {FONTS.map(f=><option key={f} value={f} style={{fontFamily:f}}>{f}</option>)}
        </select>
        <input type="number" min={8} max={144} value={fontSize} onChange={e=>{setFontSize(Number(e.target.value));updateSelectedText({fontSize:Number(e.target.value)});}}
          className="h-6 w-12 text-[10px] border border-gray-200 rounded px-1 bg-white text-gray-700 focus:outline-none focus:border-blue-400"/>
        <div className="w-px h-4 bg-gray-200 mx-0.5"/>
        <button onClick={()=>{setIsBold(!isBold);updateSelectedText({fontWeight:!isBold?"bold":"normal"});}} className={`w-6 h-6 flex items-center justify-center rounded text-xs font-bold transition ${isBold?"bg-blue-100 text-blue-700":"text-gray-500 hover:bg-gray-100"}`}>B</button>
        <button onClick={()=>{setIsItalic(!isItalic);updateSelectedText({fontStyle:!isItalic?"italic":"normal"});}} className={`w-6 h-6 flex items-center justify-center rounded text-xs italic font-medium transition ${isItalic?"bg-blue-100 text-blue-700":"text-gray-500 hover:bg-gray-100"}`}>I</button>
        <button onClick={()=>{setIsUnderline(!isUnderline);updateSelectedText({underline:!isUnderline});}} className={`w-6 h-6 flex items-center justify-center rounded text-xs underline font-medium transition ${isUnderline?"bg-blue-100 text-blue-700":"text-gray-500 hover:bg-gray-100"}`}>U</button>
        <div className="w-px h-4 bg-gray-200 mx-0.5"/>
        {(["left","center","right"] as const).map(align=>(
          <button key={align} onClick={()=>updateSelectedText({textAlign:align})} className="w-6 h-6 flex items-center justify-center rounded text-gray-500 hover:bg-gray-100 transition" title={`Align ${align}`}>
            <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
              {align==="left"  && <><line x1="3" y1="6" x2="21" y2="6"/><line x1="3" y1="12" x2="15" y2="12"/><line x1="3" y1="18" x2="18" y2="18"/></>}
              {align==="center"&& <><line x1="3" y1="6" x2="21" y2="6"/><line x1="6" y1="12" x2="18" y2="12"/><line x1="4" y1="18" x2="20" y2="18"/></>}
              {align==="right" && <><line x1="3" y1="6" x2="21" y2="6"/><line x1="9" y1="12" x2="21" y2="12"/><line x1="6" y1="18" x2="21" y2="18"/></>}
            </svg>
          </button>
        ))}
        <div className="ml-auto">
          <span className="text-[9px] text-gray-300">V=Select P=Pen E=Eraser R=Rect C=Circle T=Text Del=Delete Ctrl+Z=Undo</span>
        </div>
      </div>

      {/* CANVAS */}
      <div className="flex-1 overflow-hidden relative" style={{minHeight:0}}>
        {!isReady && (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-white gap-2 z-10">
            <div className="w-5 h-5 border-2 border-blue-500 border-t-transparent rounded-full animate-spin"/>
            <span className="text-[11px] text-gray-400 uppercase tracking-widest">Loading canvas</span>
          </div>
        )}
        <canvas ref={canvasRef} className="block"/>
      </div>

      {/* STATUS BAR */}
      <div className="flex items-center justify-between px-3 py-1 bg-gray-50 border-t border-gray-200 shrink-0">
        <div className="flex items-center gap-3 text-[9px] text-gray-400">
          <span>Tool: <span className="font-medium text-gray-600">{activeTool}</span></span>
          <span>Size: {brushSize}px</span>
          <span>Opacity: {opacity}%</span>
          <span>Zoom: {zoom}%</span>
          <span>Undo: {undoStack.length}</span>
        </div>
        <div className="flex items-center gap-2 text-[9px] text-gray-400">
          {saving && <span className="text-amber-500 animate-pulse">● Saving…</span>}
          {!saving && savedAt && <span className="text-emerald-500">✓ Saved {savedAt}</span>}
          <span className="font-mono">{roomIdState.substring(0,8)}</span>
        </div>
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect, useRef, useCallback } from "react";

type Tool = "pen" | "select" | "eraser" | "rectangle" | "circle" | "triangle" | "line" | "text" |"arrow" | "double-arrow" | "dashed-arrow" | "sticky" | "highlighter";

// ✅ Fixed default board dimensions
const DEFAULT_WIDTH = 1400;
const DEFAULT_HEIGHT = 800;

export default function WhiteboardView({ databaseId }: { databaseId: string }) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const fabricRef = useRef<any>(null);
  const fabricLibRef = useRef<any>(null);
  const drawingShapeRef = useRef<any>(null);
  const startPointRef = useRef<{ x: number; y: number } | null>(null);
  const isDrawingRef = useRef(false);
  const suppressUndoRef = useRef(false);
  const saveTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const [isReady, setIsReady] = useState(false);
  const [activeTool, setActiveTool] = useState<Tool>("pen");
  const [activeColor, setActiveColor] = useState("#ffffff");
  const [fillColor, setFillColor] = useState("transparent");
  const [boardColor, setBoardColor] = useState("#1a1a2e");
  const [brushSize, setBrushSize] = useState(3);
  const [fontSize, setFontSize] = useState(18);
  const [opacity, setOpacity] = useState(100);
  const [isBold, setIsBold] = useState(false);
  const [isItalic, setIsItalic] = useState(false);
  const [undoStack, setUndoStack] = useState<any[]>([]);
  const [redoStack, setRedoStack] = useState<any[]>([]);
  const [saving, setSaving] = useState(false);
  const [savedAt, setSavedAt] = useState<string | null>(null);
  const [showShareModal, setShowShareModal] = useState(false);
  const [copied, setCopied] = useState(false);
  const [zoom, setZoom] = useState(100);
  const [boardWidth, setBoardWidth] = useState(DEFAULT_WIDTH);
  const [boardHeight, setBoardHeight] = useState(DEFAULT_HEIGHT);
  const [showSizeMenu, setShowSizeMenu] = useState(false);
  const [showColorPicker, setShowColorPicker] = useState<"stroke" | "fill" | "board" | null>(null);
  const colorPickerRef = useRef<HTMLDivElement>(null);
  const sizeMenuRef = useRef<HTMLDivElement>(null);

const applyDotBackground = (canvas: any) => {
  // Keep Fabric canvas transparent.
  // Dot background is rendered by the container so erasing can reveal it cleanly.
  canvas.setBackgroundColor("rgba(0,0,0,0)", canvas.renderAll.bind(canvas));
};

  const normalizeShapeSelectionStyle = (canvas: any) => {
    canvas.getObjects().forEach((obj: any) => {
      const isText = obj?.type === "i-text" || obj?.type === "textbox";
      if (!isText) {
        obj.set({ hasControls: false, hasBorders: false, transparentCorners: true });
      }
    });
  };

  const getDotColorForBackground = (color: string) => {
    const hex = color.replace("#", "");
    const normalized = hex.length === 3
      ? hex.split("").map((ch) => ch + ch).join("")
      : hex;
    const r = parseInt(normalized.slice(0, 2), 16) || 0;
    const g = parseInt(normalized.slice(2, 4), 16) || 0;
    const b = parseInt(normalized.slice(4, 6), 16) || 0;
    const luminance = (0.2126 * r + 0.7152 * g + 0.0722 * b) / 255;

    return luminance > 0.6 ? "rgba(0,0,0,0.20)" : "rgba(255,255,255,0.35)";
  };

  const getContrastStrokeColor = (color: string) => {
    const hex = color.replace("#", "");
    const normalized = hex.length === 3
      ? hex.split("").map((ch) => ch + ch).join("")
      : hex;
    const r = parseInt(normalized.slice(0, 2), 16) || 0;
    const g = parseInt(normalized.slice(2, 4), 16) || 0;
    const b = parseInt(normalized.slice(4, 6), 16) || 0;
    const luminance = (0.2126 * r + 0.7152 * g + 0.0722 * b) / 255;

    return luminance > 0.6 ? "#111111" : "#ffffff";
  };

  // ── Close dropdowns on outside click ──
  useEffect(() => {
    const handler = (e: MouseEvent) => {
      if (colorPickerRef.current && !colorPickerRef.current.contains(e.target as Node)) {
        setShowColorPicker(null);
      }
      if (sizeMenuRef.current && !sizeMenuRef.current.contains(e.target as Node)) {
        setShowSizeMenu(false);
      }
    };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, []);

  // ── Apply board color ──
  // useEffect(() => {
  //   const canvas = fabricRef.current;
  //   if (!canvas) return;
  //   // canvas.setBackgroundColor(boardColor, () => canvas.renderAll());
  //   canvas.setBackgroundColor(boardColor, () => canvas.renderAll());
  // }, [boardColor]);

  useEffect(() => {
  const canvas = fabricRef.current;
  if (!canvas) return;

  applyDotBackground(canvas);
}, [boardColor]);

    useEffect(() => {
      setActiveColor(getContrastStrokeColor(boardColor));
    }, [boardColor]);
  // ── Resize board ──
  const resizeBoard = useCallback((w: number, h: number) => {
    const canvas = fabricRef.current;
    if (!canvas) return;
    setBoardWidth(w);
    setBoardHeight(h);
    canvas.setWidth(w);
    canvas.setHeight(h);
    applyDotBackground(canvas);
    canvas.renderAll();
  }, [boardColor]);

  // ── Save to DB ──
  const saveToDatabase = useCallback(async (json: any) => {
    if (!databaseId) return;
    setSaving(true);
    try {
      await fetch(`/api/databases/${databaseId}/whiteboard`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ canvas: json }),
      });
      setSavedAt(new Date().toLocaleTimeString());
    } catch (err) {
      console.error("Save failed:", err);
    } finally {
      setSaving(false);
    }
  }, [databaseId]);

  // ── Load from DB ──
  const loadFromDatabase = useCallback(async () => {
    if (!databaseId || !fabricRef.current) return;
    try {
      const res = await fetch(`/api/databases/${databaseId}/whiteboard`);
      const data = await res.json();
      if (data.canvas && fabricRef.current) {
        fabricRef.current.loadFromJSON(data.canvas, () => {
          normalizeShapeSelectionStyle(fabricRef.current);
          applyDotBackground(fabricRef.current);
          fabricRef.current.renderAll();
        });
      }
    } catch (err) {
      console.error("Load failed:", err);
    }
  }, [databaseId, boardColor]);

  // ── Push undo ──
  const pushUndo = useCallback(() => {
    if (suppressUndoRef.current) return;
    const canvas = fabricRef.current;
    if (!canvas) return;
    const json = canvas.toJSON();
    setUndoStack((prev) => [...prev.slice(-29), json]);
    setRedoStack([]);
    if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
    saveTimerRef.current = setTimeout(() => saveToDatabase(json), 2000);
  }, [saveToDatabase]);

  // ── Init Fabric ──
  useEffect(() => {
    if (!canvasRef.current) return;
    let disposed = false;

    import("fabric").then((mod) => {
      if (disposed) return;
      const fabric = (mod.fabric ?? mod) as any;
      if (!fabric.EraserBrush && (mod as any).EraserBrush) {
        fabric.EraserBrush = (mod as any).EraserBrush;
      }
      fabricLibRef.current = fabric;

      // ✅ Fixed size canvas
      const canvas = new fabric.Canvas(canvasRef.current, {
        isDrawingMode: true,
        backgroundColor: "#1a1a2e",
        width: DEFAULT_WIDTH,
        height: DEFAULT_HEIGHT,
        preserveObjectStacking: true,
        renderOnAddRemove: false,
      });

      const brush = new fabric.PencilBrush(canvas);
      brush.color = "#ffffff";
      brush.width = 3;
      canvas.freeDrawingBrush = brush;

      fabricRef.current = canvas;
      setIsReady(true);

      canvas.on("object:added",    () => { if (!suppressUndoRef.current) pushUndo(); });
      canvas.on("object:modified", () => { if (!suppressUndoRef.current) pushUndo(); });
      canvas.on("object:removed",  () => { if (!suppressUndoRef.current) pushUndo(); });

      setTimeout(() => loadFromDatabase(), 300);
    }).catch((err) => console.error("Fabric load failed:", err));

    return () => {
      disposed = true;
      if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
      fabricRef.current?.dispose();
    };
  }, []);

  // ── Tool sync ──
  useEffect(() => {
    const canvas = fabricRef.current;
    const fabric = fabricLibRef.current;
    if (!canvas || !fabric) return;

    canvas.off("mouse:down");
    canvas.off("mouse:move");
    canvas.off("mouse:up");
    canvas.off("path:created");

    if (activeTool === "pen") {
      canvas.isDrawingMode = true;
      canvas.selection = true;
      canvas.defaultCursor = "crosshair";
      const brush = new fabric.PencilBrush(canvas);
      brush.color = activeColor;
      brush.width = brushSize;
      canvas.freeDrawingBrush = brush;
    } else if (activeTool === "highlighter") {
      canvas.isDrawingMode = true;
      canvas.selection = true;
      const brush = new fabric.PencilBrush(canvas);
      brush.color = activeColor + "66";
      brush.width = brushSize * 6;
      canvas.freeDrawingBrush = brush;
    } else if (activeTool === "eraser") {
      canvas.selection = false;
      canvas.defaultCursor = "cell";

      const hasNativeEraser = typeof fabric.EraserBrush === "function";

      if (hasNativeEraser) {
        canvas.isDrawingMode = true;
        const brush = new fabric.EraserBrush(canvas);
        // Keep erasing precise while still usable.
        brush.width = Math.max(2, brushSize * 2.5);
        canvas.freeDrawingBrush = brush;

        let erasedSomething = false;

        const onMouseDown = () => {
          canvas.getObjects().forEach((obj: any) => {
            if (obj.erasable !== false) {
              obj.set("erasable", true);
            }
          });
          suppressUndoRef.current = true;
        };

        const onPathCreated = (opt: any) => {
          if (!opt?.path) return;
          erasedSomething = true;
          canvas.requestRenderAll();
        };

        const onMouseUp = () => {
          suppressUndoRef.current = false;
          if (erasedSomething) {
            pushUndo();
            erasedSomething = false;
          }
        };

        canvas.on("mouse:down", onMouseDown);
        canvas.on("path:created", onPathCreated);
        canvas.on("mouse:up", onMouseUp);

        return () => {
          canvas.off("mouse:down", onMouseDown);
          canvas.off("path:created", onPathCreated);
          canvas.off("mouse:up", onMouseUp);
          suppressUndoRef.current = false;
        };
      }

      // Fallback: transparent pixel erase for precise erasing when native
      // EraserBrush is unavailable in the current Fabric build.
      // Use object hit-delete fallback to avoid persisted erase-mask artifacts.
      canvas.isDrawingMode = false;

      let erasedSomething = false;
      let isErasing = false;

      const eraseAtPointer = (opt: any) => {
        const pointer = canvas.getPointer(opt.e);
        const radius = Math.max(4, brushSize * 4);
        const topLeft = new fabric.Point(pointer.x - radius, pointer.y - radius);
        const bottomRight = new fabric.Point(pointer.x + radius, pointer.y + radius);
        const hitPoint = new fabric.Point(pointer.x, pointer.y);

        const toRemove = canvas.getObjects().filter((obj: any) => {
          if (!obj || obj.evented === false) return false;
          return obj.intersectsWithRect(topLeft, bottomRight, true) || obj.containsPoint(hitPoint);
        });

        if (toRemove.length > 0) {
          toRemove.forEach((obj: any) => canvas.remove(obj));
          erasedSomething = true;
          canvas.requestRenderAll();
        }
      };

      const onMouseDown = (opt: any) => {
        isErasing = true;
        suppressUndoRef.current = true;
        eraseAtPointer(opt);
      };

      const onMouseMove = (opt: any) => {
        if (!isErasing) return;
        eraseAtPointer(opt);
      };

      const onMouseUp = () => {
        isErasing = false;
        suppressUndoRef.current = false;
        if (erasedSomething) {
          pushUndo();
          erasedSomething = false;
        }
      };

      canvas.on("mouse:down", onMouseDown);
      canvas.on("mouse:move", onMouseMove);
      canvas.on("mouse:up", onMouseUp);

      return () => {
        canvas.off("mouse:down", onMouseDown);
        canvas.off("mouse:move", onMouseMove);
        canvas.off("mouse:up", onMouseUp);
        suppressUndoRef.current = false;
      };
    } else if (activeTool === "select") {
      canvas.isDrawingMode = false;
      canvas.selection = true;
      canvas.defaultCursor = "default";
    } else {
      canvas.isDrawingMode = false;
      canvas.selection = false;
      canvas.defaultCursor = "crosshair";

      const setArrowHeadFromTip = (
        head: any,
        tipX: number,
        tipY: number,
        angleRad: number,
        width: number,
        height: number
      ) => {
        // Fabric triangle is positioned by its center. Move center behind the tip
        // so the arrow tip is exactly on the line endpoint.
        const cx = tipX - Math.cos(angleRad) * (height / 2);
        const cy = tipY - Math.sin(angleRad) * (height / 2);
        head.set({
          left: cx,
          top: cy,
          angle: angleRad * (180 / Math.PI) + 90,
          width,
          height,
        });
      };

      const onMouseDown = (opt: any) => {
        suppressUndoRef.current = true;
        const pointer = canvas.getPointer(opt.e);
        startPointRef.current = { x: pointer.x, y: pointer.y };
        isDrawingRef.current = true;

        const fill = fillColor === "transparent" ? "rgba(0,0,0,0)" : fillColor;
        let shape: any = null;

        if (activeTool === "rectangle") {
          shape = new fabric.Rect({
            left: pointer.x, top: pointer.y, width: 0, height: 0,
            fill, stroke: activeColor, strokeWidth: brushSize,
            opacity: opacity / 100, selectable: false, evented: false,
          });
        } else if (activeTool === "circle") {
          shape = new fabric.Ellipse({
            left: pointer.x, top: pointer.y, rx: 0, ry: 0,
            fill, stroke: activeColor, strokeWidth: brushSize,
            opacity: opacity / 100, selectable: false, evented: false,
          });
        } else if (activeTool === "triangle") {
          shape = new fabric.Triangle({
            left: pointer.x, top: pointer.y, width: 0, height: 0,
            fill, stroke: activeColor, strokeWidth: brushSize,
            opacity: opacity / 100, selectable: false, evented: false,
          });
        } else if (activeTool === "line") {
          shape = new fabric.Line(
            [pointer.x, pointer.y, pointer.x, pointer.y],
            { stroke: activeColor, strokeWidth: brushSize, opacity: opacity / 100, selectable: false, evented: false }
          );
        }
        else if (
  // activeTool === "line" ||
  activeTool === "arrow" ||
  activeTool === "double-arrow" ||
  activeTool === "dashed-arrow"
) {
  shape = new fabric.Line(
    [pointer.x, pointer.y, pointer.x, pointer.y],
    {
      stroke: activeColor,
      strokeWidth: brushSize,
      opacity: opacity / 100,
      selectable: false,
      evented: false,
      strokeDashArray: activeTool === "dashed-arrow" ? [6, 4] : undefined,
    }
  );
}

        if (shape) {

  // ✅ ADD ARROWHEAD LOGIC HERE
  if (
    activeTool === "arrow" ||
    activeTool === "double-arrow" ||
    activeTool === "dashed-arrow"
  ) {
    const lineStrokeWidth = Number(shape.strokeWidth ?? brushSize);
    const arrowHeadWidth = Math.max(12, lineStrokeWidth * 4);
    const arrowHeadHeight = Math.max(16, lineStrokeWidth * 5);

    const arrowHead = new fabric.Triangle({
      width: arrowHeadWidth,
      height: arrowHeadHeight,
      fill: activeColor,
      opacity: opacity / 100,
      left: pointer.x,
      top: pointer.y,
      originX: "center",
      originY: "center",
      selectable: false,
      evented: false,
    });

    shape.arrowHead = arrowHead;
    setArrowHeadFromTip(arrowHead, pointer.x, pointer.y, 0, arrowHeadWidth, arrowHeadHeight);

    // ✅ Double arrow start head
    if (activeTool === "double-arrow") {
      const startHead = new fabric.Triangle({
        width: arrowHeadWidth,
        height: arrowHeadHeight,
        fill: activeColor,
        opacity: opacity / 100,
        left: pointer.x,
        top: pointer.y,
        angle: 180,
        originX: "center",
        originY: "center",
        selectable: false,
        evented: false,
      });

      shape.startHead = startHead;
      setArrowHeadFromTip(startHead, pointer.x, pointer.y, Math.PI, arrowHeadWidth, arrowHeadHeight);
      canvas.add(startHead);
    }

    canvas.add(arrowHead);
  }

  // ✅ ORIGINAL CODE
  canvas.add(shape);
  canvas.renderAll();
  drawingShapeRef.current = shape;
}
      };

      const onMouseMove = (opt: any) => {
        if (!isDrawingRef.current || !startPointRef.current || !drawingShapeRef.current) return;
        const pointer = canvas.getPointer(opt.e);
        const sp = startPointRef.current;
        const shape = drawingShapeRef.current;

        if (activeTool === "rectangle" || activeTool === "triangle") {
          shape.set({
            left: Math.min(pointer.x, sp.x), top: Math.min(pointer.y, sp.y),
            width: Math.abs(pointer.x - sp.x) || 1, height: Math.abs(pointer.y - sp.y) || 1,
          });
          shape.setCoords();
        } else if (activeTool === "circle") {
          shape.set({
            left: Math.min(pointer.x, sp.x), top: Math.min(pointer.y, sp.y),
            rx: Math.abs(pointer.x - sp.x) / 2 || 1, ry: Math.abs(pointer.y - sp.y) / 2 || 1,
          });
          shape.setCoords();
        } else if (
  activeTool === "line" ||
  activeTool === "arrow" ||
  activeTool === "double-arrow" ||
  activeTool === "dashed-arrow"
) {
  shape.set({ x2: pointer.x, y2: pointer.y });

  const angleRad = Math.atan2(pointer.y - sp.y, pointer.x - sp.x);

  const lineStrokeWidth = Number(shape.strokeWidth ?? brushSize);
  const arrowHeadWidth = Math.max(12, lineStrokeWidth * 4);
  const arrowHeadHeight = Math.max(16, lineStrokeWidth * 5);

  // ✅ End arrow head
  if (shape.arrowHead) {
    setArrowHeadFromTip(shape.arrowHead, pointer.x, pointer.y, angleRad, arrowHeadWidth, arrowHeadHeight);
  }

  // ✅ Start arrow head (for double arrow)
  if (shape.startHead) {
    setArrowHeadFromTip(shape.startHead, sp.x, sp.y, angleRad + Math.PI, arrowHeadWidth, arrowHeadHeight);
  }
}
        
        canvas.requestRenderAll();
      };

      const onMouseUp = (opt: any) => {
        if (!isDrawingRef.current) return;
        isDrawingRef.current = false;
        const sp = startPointRef.current;
        const shape = drawingShapeRef.current;
        if (!shape) {
          startPointRef.current = null;
          suppressUndoRef.current = false;
          return;
        }

        const pointer = opt?.e ? canvas.getPointer(opt.e) : null;
        const drawDistance = sp && pointer
          ? Math.hypot(pointer.x - sp.x, pointer.y - sp.y)
          : 0;

        if (shape && activeTool.includes("arrow")) {
          if (drawDistance < 2) {
            canvas.remove(shape);
            if (shape.arrowHead) canvas.remove(shape.arrowHead);
            if (shape.startHead) canvas.remove(shape.startHead);
            drawingShapeRef.current = null;
            startPointRef.current = null;
            canvas.discardActiveObject();
            canvas.requestRenderAll();
            suppressUndoRef.current = false;
            return;
          }

          const objects = [shape];
          if (shape.arrowHead) objects.push(shape.arrowHead);
          if (shape.startHead) objects.push(shape.startHead);

          const group = new fabric.Group(objects, {
            selectable: true,
            evented: true,
            hasControls: false,
            hasBorders: false,
            transparentCorners: true,
          });

          canvas.remove(shape);
          if (shape.arrowHead) canvas.remove(shape.arrowHead);
          if (shape.startHead) canvas.remove(shape.startHead);

          canvas.add(group);
          drawingShapeRef.current = null;
          startPointRef.current = null;
          canvas.discardActiveObject();
          canvas.requestRenderAll();
          suppressUndoRef.current = false;
          pushUndo();
        } else {
          // Prevent accidental click artifacts (tiny 1x1 extra square).
          if (drawDistance < 2) {
            canvas.remove(shape);
          } else {
            shape.set({ selectable: true, evented: true, hasControls: false, hasBorders: false, transparentCorners: true });
            shape.setCoords();
          }

          drawingShapeRef.current = null;
          startPointRef.current = null;
          canvas.requestRenderAll();
          suppressUndoRef.current = false;
          pushUndo();
        }
      };
      

      canvas.on("mouse:down", onMouseDown);
      canvas.on("mouse:move", onMouseMove);
      canvas.on("mouse:up", onMouseUp);

      return () => {
        canvas.off("mouse:down", onMouseDown);
        canvas.off("mouse:move", onMouseMove);
        canvas.off("mouse:up", onMouseUp);
        canvas.selection = true;
        canvas.defaultCursor = "default";
      };
    }
  }, [activeTool, activeColor, fillColor, boardColor, brushSize, opacity, pushUndo]);

  // ── Add text ──
  const addText = async (sticky = false) => {
    const fabric = fabricLibRef.current;
    const canvas = fabricRef.current;
    if (!fabric || !canvas) return;

    if (sticky) {
      const rect = new fabric.Rect({ width: 170, height: 120, fill: "#fef08a", stroke: "#ca8a04", strokeWidth: 1, rx: 4 });
      const text = new fabric.IText("Sticky note", { left: 85, top: 60, fill: "#713f12", fontSize: 14, fontFamily: "sans-serif", originX: "center", originY: "center" });
      const group = new fabric.Group([rect, text], { left: 100, top: 100 });
      canvas.add(group);
    } else {
      const text = new fabric.IText("Type here...", {
        left: 120, top: 120, fill: activeColor, fontSize,
        fontFamily: "sans-serif",
        fontWeight: isBold ? "bold" : "normal",
        fontStyle: isItalic ? "italic" : "normal",
        opacity: opacity / 100,
      });
      canvas.add(text);
      canvas.setActiveObject(text);
      text.enterEditing();
    }
    setActiveTool("select");
    pushUndo();
  };

  // ── Undo / Redo ──
  const handleUndo = useCallback(() => {
    const canvas = fabricRef.current;
    if (!canvas || undoStack.length === 0) return;
    const current = canvas.toJSON();
    const prev = undoStack[undoStack.length - 1];
    setRedoStack((r) => [...r, current]);
    setUndoStack((u) => u.slice(0, -1));
    suppressUndoRef.current = true;
    canvas.loadFromJSON(prev, () => { canvas.renderAll(); suppressUndoRef.current = false; });
  }, [undoStack]);

  const handleRedo = useCallback(() => {
    const canvas = fabricRef.current;
    if (!canvas || redoStack.length === 0) return;
    const current = canvas.toJSON();
    const next = redoStack[redoStack.length - 1];
    setUndoStack((u) => [...u, current]);
    setRedoStack((r) => r.slice(0, -1));
    suppressUndoRef.current = true;
    canvas.loadFromJSON(next, () => { canvas.renderAll(); suppressUndoRef.current = false; });
  }, [redoStack]);

  const deleteSelected = () => {
    const canvas = fabricRef.current;
    if (!canvas) return;
    canvas.getActiveObjects().forEach((obj: any) => canvas.remove(obj));
    canvas.discardActiveObject();
    canvas.renderAll();
    pushUndo();
  };

  const handleClear = () => {
    if (!confirm("Clear the entire canvas?")) return;
    const canvas = fabricRef.current;
    if (!canvas) return;
    suppressUndoRef.current = true;
    canvas.clear();
    applyDotBackground(canvas);
    canvas.renderAll();
    suppressUndoRef.current = false;
    pushUndo();
  };

  const handleDownload = () => {
    const canvas = fabricRef.current;
    if (!canvas) return;
    const url = canvas.toDataURL({ format: "png", multiplier: 2 });
    const a = document.createElement("a");
    a.href = url;
    a.download = `whiteboard-${Date.now()}.png`;
    a.click();
  };

  const handleZoom = (delta: number) => {
    const canvas = fabricRef.current;
    if (!canvas) return;
    const newZoom = Math.min(Math.max(zoom + delta, 25), 400);
    setZoom(newZoom);
    canvas.setZoom(newZoom / 100);
    canvas.renderAll();
  };

  const handleManualSave = () => {
    const canvas = fabricRef.current;
    if (!canvas) return;
    saveToDatabase(canvas.toJSON());
  };

  const handleCopy = () => {
    navigator.clipboard.writeText(`${window.location.origin}?whiteboard=${databaseId}`);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  // ── Keyboard shortcuts ──
  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      const tag = (e.target as HTMLElement).tagName;
      if (tag === "INPUT" || tag === "TEXTAREA") return;
      if ((e.ctrlKey || e.metaKey) && e.key === "z") { e.preventDefault(); handleUndo(); }
      if ((e.ctrlKey || e.metaKey) && e.key === "y") { e.preventDefault(); handleRedo(); }
      if ((e.ctrlKey || e.metaKey) && e.key === "s") { e.preventDefault(); handleManualSave(); }
      if ((e.key === "Delete" || e.key === "Backspace") && fabricRef.current?.getActiveObject()) {
        e.preventDefault(); deleteSelected();
      }
      if (!e.ctrlKey && !e.metaKey) {
        if (e.key === "v") setActiveTool("select");
        if (e.key === "p") setActiveTool("pen");
        if (e.key === "e") setActiveTool("eraser");
        if (e.key === "r") setActiveTool("rectangle");
        if (e.key === "c") setActiveTool("circle");
        if (e.key === "t") addText(false);
      }
    };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, [handleUndo, handleRedo, activeTool]);

  const STROKE_COLORS = [
    "#ffffff","#000000","#ef4444","#f97316","#eab308",
    "#22c55e","#3b82f6","#8b5cf6","#ec4899","#06b6d4",
    "#a3a3a3","#fbbf24","#34d399","#60a5fa","#f472b6",
  ];

  const BOARD_COLORS = [
    "#1a1a2e","#0f0f13","#ffffff","#f8fafc","#1e293b",
    "#0f172a","#18181b","#fef9c3","#ecfdf5","#eff6ff",
  ];

  // ✅ Preset board sizes
  const BOARD_SIZES = [
    { label: "Small",       w: 800,  h: 500,  desc: "800×500" },
    { label: "Default",     w: 1400, h: 800,  desc: "1400×800" },
    { label: "Large",       w: 1920, h: 1080, desc: "1920×1080 (HD)" },
    { label: "A4 Portrait", w: 794,  h: 1123, desc: "A4 Portrait" },
    { label: "A4 Landscape",w: 1123, h: 794,  desc: "A4 Landscape" },
    { label: "Square",      w: 1000, h: 1000, desc: "1000×1000" },
    { label: "4K",          w: 3840, h: 2160, desc: "3840×2160 (4K)" },
  ];

  const ToolBtn = ({ tool, icon, title, shortcut, onClick }: {
    tool?: Tool; icon: React.ReactNode; title: string; shortcut?: string; onClick?: () => void;
  }) => (
    <button
      onClick={onClick ?? (() => tool && setActiveTool(tool))}
      title={`${title}${shortcut ? ` (${shortcut})` : ""}`}
      className={`w-7 h-7 flex items-center justify-center rounded-md transition-all
        ${tool && activeTool === tool
          ? "bg-violet-600 text-white shadow-sm shadow-violet-500/30"
          : "text-gray-400 hover:bg-white/10 hover:text-white"
        }`}
    >
      {icon}
    </button>
  );

  return (
    <div className="flex flex-col w-full h-full overflow-hidden bg-[#0d0d0f] rounded-xl border border-white/6">

      <div className="absolute top-19 rounded-xl z-30 w-full pr-2">
      {/* ══ TOOLBAR ROW 1 ══ */}
      <div className="flex items-center gap-0.5 px-2 py-1.5 bg-[#111114] border-b border-white/6 shrink-0 flex-wrap">

        {/* Title */}
        <div className="flex items-center gap-1.5 pr-2 border-r border-white/10">
          <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" className="text-violet-400 shrink-0">
            <path d="M12 20h9"/><path d="M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4Z"/>
          </svg>
          <span className="text-white text-[11px] font-semibold tracking-tight">Whiteboard</span>
          <span className={`w-1.5 h-1.5 rounded-full ${isReady ? "bg-emerald-400" : "bg-amber-400"}`} />
        </div>

        {/* File ops */}
        <div className="flex items-center gap-0.5 px-2 border-r border-white/10">
          <ToolBtn title="Save" shortcut="Ctrl+S" onClick={handleManualSave}
            icon={saving
              ? <div className="w-3 h-3 border border-violet-400 border-t-transparent rounded-full animate-spin" />
              : <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M19 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11l5 5v11a2 2 0 0 1-2 2z"/><polyline points="17 21 17 13 7 13 7 21"/><polyline points="7 3 7 8 15 8"/></svg>
            }
          />
          <ToolBtn title="Download PNG" onClick={handleDownload}
            icon={<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg>}
          />
          <ToolBtn title="Share" onClick={() => setShowShareModal(true)}
            icon={<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><circle cx="18" cy="5" r="3"/><circle cx="6" cy="12" r="3"/><circle cx="18" cy="19" r="3"/><line x1="8.59" y1="13.51" x2="15.42" y2="17.49"/><line x1="15.41" y1="6.51" x2="8.59" y2="10.49"/></svg>}
          />
        </div>

        {/* Edit ops */}
        <div className="flex items-center gap-0.5 px-2 border-r border-white/10">
          <ToolBtn title="Undo" shortcut="Ctrl+Z" onClick={handleUndo}
            icon={<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><polyline points="9 14 4 9 9 4"/><path d="M20 20v-7a4 4 0 0 0-4-4H4"/></svg>}
          />
          <ToolBtn title="Redo" shortcut="Ctrl+Y" onClick={handleRedo}
            icon={<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><polyline points="15 14 20 9 15 4"/><path d="M4 20v-7a4 4 0 0 1 4-4h12"/></svg>}
          />
          <ToolBtn title="Delete selected" shortcut="Del" onClick={deleteSelected}
            icon={<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><polyline points="3 6 5 6 21 6"/><path d="M19 6l-1 14H6L5 6"/><path d="M10 11v6"/><path d="M14 11v6"/><path d="M9 6V4h6v2"/></svg>}
          />
          <ToolBtn title="Clear canvas" onClick={handleClear}
            icon={<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M20 20H7L3 16l10-10 7 7-2.5 2.5"/><path d="M6 11l4 4"/></svg>}
          />
        </div>

        {/* Zoom */}
        <div className="flex items-center gap-1 px-2 border-r border-white/10">
          <button onClick={() => handleZoom(-10)} className="w-5 h-5 flex items-center justify-center rounded text-gray-400 hover:text-white hover:bg-white/10 text-sm font-bold">−</button>
          <span className="text-[10px] text-gray-500 w-9 text-center">{zoom}%</span>
          <button onClick={() => handleZoom(10)} className="w-5 h-5 flex items-center justify-center rounded text-gray-400 hover:text-white hover:bg-white/10 text-sm font-bold">+</button>
          <button onClick={() => { setZoom(100); fabricRef.current?.setZoom(1); fabricRef.current?.renderAll(); }}
            className="text-[9px] text-gray-500 hover:text-gray-300 px-1 transition">Reset</button>
        </div>

        {/* ✅ Board size picker */}
        <div className="relative px-2 border-r border-white/10" ref={sizeMenuRef}>
          <button
            onClick={() => setShowSizeMenu(!showSizeMenu)}
            className="flex items-center gap-1.5 h-6 px-2 rounded-md text-[10px] text-gray-400 hover:text-white hover:bg-white/10 transition border border-white/10"
          >
            <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
              <rect x="3" y="3" width="18" height="18" rx="2"/>
              <path d="M3 9h18M9 3v18"/>
            </svg>
            <span>{boardWidth}×{boardHeight}</span>
            <svg width="8" height="8" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
              <polyline points="6 9 12 15 18 9"/>
            </svg>
          </button>

          {showSizeMenu && (
            <div className="absolute top-full left-0 mt-1 z-50 bg-[#111114] border border-white/10 rounded-xl shadow-2xl p-2 w-52">
              <p className="text-[9px] font-semibold text-gray-500 uppercase tracking-wider px-2 mb-1.5">Board Size</p>
              <div className="space-y-0.5">
                {BOARD_SIZES.map((size) => (
                  <button
                    key={size.label}
                    onClick={() => { resizeBoard(size.w, size.h); setShowSizeMenu(false); }}
                    className={`w-full flex items-center justify-between px-2.5 py-1.5 rounded-lg text-[10px] transition ${
                      boardWidth === size.w && boardHeight === size.h
                        ? "bg-violet-600/20 text-violet-300 border border-violet-500/30"
                        : "text-gray-400 hover:bg-white/5 hover:text-white"
                    }`}
                  >
                    <span className="font-medium">{size.label}</span>
                    <span className="text-gray-600">{size.desc}</span>
                  </button>
                ))}
              </div>

              {/* Custom size inputs */}
              <div className="mt-2 pt-2 border-t border-white/10 px-2">
                <p className="text-[9px] text-gray-500 mb-1.5">Custom</p>
                <div className="flex items-center gap-1">
                  <input
                    type="number" min={100} max={8000}
                    defaultValue={boardWidth}
                    onBlur={(e) => {
                      const w = Math.min(8000, Math.max(100, Number(e.target.value)));
                      resizeBoard(w, boardHeight);
                    }}
                    className="w-16 h-5 text-[9px] bg-[#1a1a24] border border-white/10 rounded px-1 text-gray-300 focus:outline-none focus:border-violet-500"
                    placeholder="W"
                  />
                  <span className="text-[9px] text-gray-600">×</span>
                  <input
                    type="number" min={100} max={8000}
                    defaultValue={boardHeight}
                    onBlur={(e) => {
                      const h = Math.min(8000, Math.max(100, Number(e.target.value)));
                      resizeBoard(boardWidth, h);
                    }}
                    className="w-16 h-5 text-[9px] bg-[#1a1a24] border border-white/10 rounded px-1 text-gray-300 focus:outline-none focus:border-violet-500"
                    placeholder="H"
                  />
                </div>
              </div>
            </div>
          )}
        </div>

        {/* Status */}
        <div className="ml-auto flex items-center gap-2">
          {saving && <span className="text-[9px] text-amber-400 animate-pulse">● Saving…</span>}
          {!saving && savedAt && <span className="text-[9px] text-emerald-400">✓ {savedAt}</span>}
        </div>
      </div>

      {/* ══ TOOLBAR ROW 2 — Drawing Tools ══ */}
      <div className="flex items-center gap-0.5 px-2 py-1.5 bg-[#0f0f12] border-b border-white/6 shrink-0 flex-wrap">

        {/* Selection & draw */}
        <div className="flex items-center gap-0.5 pr-2 border-r border-white/10">
          <ToolBtn tool="select" title="Select" shortcut="V"
            icon={<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M5 3l14 9-7 1-4 7z"/></svg>} />
          <ToolBtn tool="pen" title="Pen" shortcut="P"
            icon={<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M12 20h9"/><path d="M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4Z"/></svg>} />
          <ToolBtn tool="highlighter" title="Highlighter"
            icon={<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="m9 11-6 6v3h3l6-6"/><path d="m22 12-4.6 4.6a2 2 0 0 1-2.8 0l-5.2-5.2a2 2 0 0 1 0-2.8L14 4"/></svg>} />
          <ToolBtn tool="eraser" title="Eraser" shortcut="E"
            icon={<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M20 20H7L3 16l10-10 7 7-2.5 2.5"/><path d="M6 11l4 4"/></svg>} />
        </div>

        {/* Shapes */}
        <div className="flex items-center gap-0.5 px-2 border-r border-white/10">
          <ToolBtn tool="rectangle" title="Rectangle" shortcut="R"
            icon={<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><rect x="3" y="5" width="18" height="14" rx="2"/></svg>} />
          <ToolBtn tool="circle" title="Ellipse" shortcut="C"
            icon={<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><ellipse cx="12" cy="12" rx="10" ry="7"/></svg>} />
          <ToolBtn tool="triangle" title="Triangle"
            icon={<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M12 3L2 21h20z"/></svg>} />
          <ToolBtn tool="line" title="Line"
            icon={<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><line x1="3" y1="21" x2="21" y2="3"/></svg>} />
        </div>

        {/* Text */}
        <div className="flex items-center gap-0.5 px-2 border-r border-white/10">
          <ToolBtn tool="text" title="Text" shortcut="T" onClick={() => addText(false)}
            icon={<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><polyline points="4 7 4 4 20 4 20 7"/><line x1="9" y1="20" x2="15" y2="20"/><line x1="12" y1="4" x2="12" y2="20"/></svg>} />
          <ToolBtn tool="sticky" title="Sticky Note" onClick={() => addText(true)}
            icon={<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M15.5 3H5a2 2 0 0 0-2 2v14c0 1.1.9 2 2 2h14a2 2 0 0 0 2-2V8.5L15.5 3Z"/><polyline points="15 3 15 9 21 9"/></svg>} />
        </div>
        <ToolBtn tool="arrow" title="Arrow"
  icon={
    <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
      <line x1="3" y1="12" x2="19" y2="12"/>
      <polyline points="13 6 19 12 13 18"/>
    </svg>
  }
/>

<ToolBtn tool="double-arrow" title="Double Arrow"
  icon={
    <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
      <line x1="3" y1="12" x2="21" y2="12"/>
      <polyline points="15 6 21 12 15 18"/>
      <polyline points="9 6 3 12 9 18"/>
    </svg>
  }
/>

<ToolBtn tool="dashed-arrow" title="Dashed Arrow"
  icon={
    <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeDasharray="3 2">
      <line x1="3" y1="12" x2="19" y2="12"/>
      <polyline points="13 6 19 12 13 18"/>
    </svg>
  }
/>

        {/* Colors */}
        <div className="flex items-center gap-1.5 px-2 border-r border-white/10 relative" ref={colorPickerRef}>
          <div className="flex flex-col items-center gap-0.5">
            <span className="text-[8px] text-gray-500">Stroke</span>
            <button onClick={() => setShowColorPicker(showColorPicker === "stroke" ? null : "stroke")}
              className="w-5 h-5 rounded border border-white/20 hover:border-white/50 transition shadow-sm"
              style={{ backgroundColor: activeColor }} />
          </div>
          <div className="flex flex-col items-center gap-0.5">
            <span className="text-[8px] text-gray-500">Fill</span>
            <button onClick={() => setShowColorPicker(showColorPicker === "fill" ? null : "fill")}
              className="w-5 h-5 rounded border border-white/20 hover:border-white/50 transition relative overflow-hidden"
              style={{ backgroundColor: fillColor === "transparent" ? "#0d0d0f" : fillColor }}>
              {fillColor === "transparent" && <div className="absolute inset-0 flex items-center justify-center"><div className="w-full h-px bg-red-500 rotate-45" /></div>}
            </button>
          </div>
          <div className="flex flex-col items-center gap-0.5">
            <span className="text-[8px] text-gray-500">Board</span>
            <button onClick={() => setShowColorPicker(showColorPicker === "board" ? null : "board")}
              className="w-5 h-5 rounded border-2 border-dashed border-white/30 hover:border-white/60 transition"
              style={{ backgroundColor: boardColor }} />
          </div>

          {showColorPicker && (
            <div className="absolute top-full left-0 mt-1 z-50 bg-[#111114] border border-white/10 rounded-xl shadow-2xl p-3 w-52">
              <p className="text-[9px] font-semibold text-gray-500 mb-2 uppercase tracking-wider">
                {showColorPicker === "stroke" ? "Stroke" : showColorPicker === "fill" ? "Fill" : "Board Background"}
              </p>
              <div className="grid grid-cols-5 gap-1.5 mb-2">
                {(showColorPicker === "board" ? BOARD_COLORS : STROKE_COLORS).map((c) => (
                  <button key={c} onClick={() => {
                    if (showColorPicker === "stroke") setActiveColor(c);
                    else if (showColorPicker === "fill") setFillColor(c);
                    else setBoardColor(c);
