import Project from "@/lib/models/Project";

export type SharePermission = "view" | "edit";

function getCookieValue(cookieHeader: string | null, name: string): string | null {
  if (!cookieHeader) return null;
  const parts = cookieHeader.split(";").map((part) => part.trim());
  const match = parts.find((part) => part.startsWith(`${name}=`));
  if (!match) return null;
  const value = match.slice(name.length + 1);
  return value ? decodeURIComponent(value) : null;
}

export function getShareTokenFromRequest(req: Request): string | null {
  return getCookieValue(req.headers.get("cookie"), "share_token");
}

export async function getSharePermissionForProject(
  projectId: string,
  shareToken: string
): Promise<SharePermission | null> {
  const project = await Project.findOne({
    _id: projectId,
    "shareLinks.token": shareToken,
  }).select("shareLinks");

  if (!project) return null;

  const link = (project.shareLinks || []).find((entry: any) => entry.token === shareToken);
  if (!link) return null;

  if (link.expiresAt && new Date(link.expiresAt) < new Date()) {
    return null;
  }

  return link.permission === "edit" ? "edit" : "view";
}

export function hasRequiredPermission(
  actual: SharePermission,
  required: SharePermission
): boolean {
  if (required === "view") return actual === "view" || actual === "edit";
  return actual === "edit";
}

